import type { BibleBook } from '../bibleData';

// Auto-generated from public-domain sources: World English Bible (WEB, EN)
// and João Ferreira de Almeida (Almeida, PT), via seven1m/open-bibles (USFX).
// Do not edit by hand — regenerate with scripts/generate-bible.

const book: BibleBook = {
  id: 'mark',
  name: 'Marcos',
  englishName: 'Mark',
  testament: 'new',
  chapters: {
    1: [
      { v: 1, en: 'The beginning of the Good News of Jesus Christ, the Son of God.', pt: 'Princípio do evangelho de Jesus Cristo, Filho de Deus.' },
      { v: 2, en: 'As it is written in the prophets, “Behold, I send my messenger before your face, who will prepare your way before you:', pt: 'Conforme está escrito no profeta Isaías: Eis que envio ante a tua face o meu mensageiro, que há de preparar o teu caminho;' },
      { v: 3, en: 'the voice of one crying in the wilderness, ‘Make ready the way of the Lord! Make his paths straight!’”', pt: 'voz do que clama no deserto: Preparai o caminho do Senhor, endireitai as suas veredas;' },
      { v: 4, en: 'John came baptizing in the wilderness and preaching the baptism of repentance for forgiveness of sins.', pt: 'assim apareceu João, o Batista, no deserto, pregando o batismo de arrependimento para remissão dos pecados.' },
      { v: 5, en: 'All the country of Judea and all those of Jerusalem went out to him. They were baptized by him in the Jordan river, confessing their sins.', pt: 'E saíam a ter com ele toda a terra da Judéia, e todos os moradores de Jerusalém; e eram por ele batizados no rio Jordão, confessando os seus pecados.' },
      { v: 6, en: 'John was clothed with camel’s hair and a leather belt around his waist. He ate locusts and wild honey.', pt: 'Ora, João usava uma veste de pêlos de camelo, e um cinto de couro em torno de seus lombos, e comia gafanhotos e mel silvestre.' },
      { v: 7, en: 'He preached, saying, “After me comes he who is mightier than I, the thong of whose sandals I am not worthy to stoop down and loosen.', pt: 'E pregava, dizendo: Após mim vem aquele que é mais poderoso do que eu, de quem não sou digno de, inclinando-me, desatar a correia das alparcas.' },
      { v: 8, en: 'I baptized you in water, but he will baptize you in the Holy Spirit.”', pt: 'Eu vos batizei em água; ele, porém, vos batizará no Espírito Santo.' },
      { v: 9, en: 'In those days, Jesus came from Nazareth of Galilee, and was baptized by John in the Jordan.', pt: 'E aconteceu naqueles dias que veio Jesus de Nazaré da Galiléia, e foi batizado por João no Jordão.' },
      { v: 10, en: 'Immediately coming up from the water, he saw the heavens parting, and the Spirit descending on him like a dove.', pt: 'E logo, quando saía da água, viu os céus se abrirem, e o Espírito, qual pomba, a descer sobre ele;' },
      { v: 11, en: 'A voice came out of the sky, “You are my beloved Son, in whom I am well pleased.”', pt: 'e ouviu-se dos céus esta voz: Tu és meu Filho amado; em ti me comprazo.' },
      { v: 12, en: 'Immediately the Spirit drove him out into the wilderness.', pt: 'Imediatamente o Espírito o impeliu para o deserto.' },
      { v: 13, en: 'He was there in the wilderness forty days tempted by Satan. He was with the wild animals; and the angels were serving him.', pt: 'E esteve no deserto quarenta dias sentado tentado por Satanás; estava entre as feras, e os anjos o serviam.' },
      { v: 14, en: 'Now after John was taken into custody, Jesus came into Galilee, preaching the Good News of God’s Kingdom,', pt: 'Ora, depois que João foi entregue, veio Jesus para a Galiléia pregando o evangelho de Deus' },
      { v: 15, en: 'and saying, “The time is fulfilled, and God’s Kingdom is at hand! Repent, and believe in the Good News.”', pt: 'e dizendo: O tempo está cumprido, e é chegado o reino de Deus. Arrependei-vos, e crede no evangelho.' },
      { v: 16, en: 'Passing along by the sea of Galilee, he saw Simon and Andrew the brother of Simon casting a net into the sea, for they were fishermen.', pt: 'E, andando junto do mar da Galiléia, viu a Simão, e a André, irmão de Simão, os quais lançavam a rede ao mar, pois eram pescadores.' },
      { v: 17, en: 'Jesus said to them, “Come after me, and I will make you into fishers for men.”', pt: 'Disse-lhes Jesus: Vinde após mim, e eu farei que vos torneis pescadores de homens.' },
      { v: 18, en: 'Immediately they left their nets, and followed him.', pt: 'Então eles, deixando imediatamente as suas redes, o seguiram.' },
      { v: 19, en: 'Going on a little further from there, he saw James the son of Zebedee, and John, his brother, who were also in the boat mending the nets.', pt: 'E ele, passando um pouco adiante, viu Tiago, filho de Zebedeu, e João, seu irmão, que estavam no barco, consertando as redes,' },
      { v: 20, en: 'Immediately he called them, and they left their father, Zebedee, in the boat with the hired servants, and went after him.', pt: 'e logo os chamou; eles, deixando seu pai Zebedeu no barco com os empregados, o seguiram.' },
      { v: 21, en: 'They went into Capernaum, and immediately on the Sabbath day he entered into the synagogue and taught.', pt: 'Entraram em Cafarnaum; e, logo no sábado, indo ele à sinagoga, pôs-se a ensinar.' },
      { v: 22, en: 'They were astonished at his teaching, for he taught them as having authority, and not as the scribes.', pt: 'E maravilhavam-se da sua doutrina, porque os ensinava como tendo autoridade, e não como os escribas.' },
      { v: 23, en: 'Immediately there was in their synagogue a man with an unclean spirit, and he cried out,', pt: 'Ora, estava na sinagoga um homem possesso dum espírito imundo, o qual gritou:' },
      { v: 24, en: 'saying, “Ha! What do we have to do with you, Jesus, you Nazarene? Have you come to destroy us? I know you who you are: the Holy One of God!”', pt: 'Que temos nós contigo, Jesus, nazareno? Vieste destruir-nos? Bem sei quem és: o Santo de Deus.' },
      { v: 25, en: 'Jesus rebuked him, saying, “Be quiet, and come out of him!”', pt: 'Mas Jesus o repreendeu, dizendo: Cala-te, e sai dele.' },
      { v: 26, en: 'The unclean spirit, convulsing him and crying with a loud voice, came out of him.', pt: 'Então o espírito imundo, convulsionando-o e clamando com grande voz, saiu dele.' },
      { v: 27, en: 'They were all amazed, so that they questioned among themselves, saying, “What is this? A new teaching? For with authority he commands even the unclean spirits, and they obey him!”', pt: 'E todos se maravilharam a ponto de perguntarem entre si, dizendo: Que é isto? Uma nova doutrina com autoridade! Pois ele ordena aos espíritos imundos, e eles lhe obedecem!' },
      { v: 28, en: 'The report of him went out immediately everywhere into all the region of Galilee and its surrounding area.', pt: 'E logo correu a sua fama por toda a região da Galiléia.' },
      { v: 29, en: 'Immediately, when they had come out of the synagogue, they came into the house of Simon and Andrew, with James and John.', pt: 'Em seguida, saiu da sinagoga e foi a casa de Simão e André com Tiago e João.' },
      { v: 30, en: 'Now Simon’s wife’s mother lay sick with a fever, and immediately they told him about her.', pt: 'A sogra de Simão estava de cama com febre, e logo lhe falaram a respeito dela.' },
      { v: 31, en: 'He came and took her by the hand, and raised her up. The fever left her, and she served them.', pt: 'Então Jesus, chegando-se e tomando-a pela mão, a levantou; e a febre a deixou, e ela os servia.' },
      { v: 32, en: 'At evening, when the sun had set, they brought to him all who were sick, and those who were possessed by demons.', pt: 'Sendo já tarde, tendo-se posto o sol, traziam-lhe todos os enfermos, e os endemoninhados;' },
      { v: 33, en: 'All the city was gathered together at the door.', pt: 'e toda a cidade estava reunida à porta;' },
      { v: 34, en: 'He healed many who were sick with various diseases, and cast out many demons. He didn’t allow the demons to speak, because they knew him.', pt: 'e ele curou muitos doentes atacados de diversas moléstias, e expulsou muitos demônios; mas não permitia que os demônios falassem, porque o conheciam.' },
      { v: 35, en: 'Early in the morning, while it was still dark, he rose up and went out, and departed into a deserted place, and prayed there.', pt: 'De madrugada, ainda bem escuro, levantou-se, saiu e foi a um lugar deserto, e ali orava.' },
      { v: 36, en: 'Simon and those who were with him followed after him;', pt: 'Foram, pois, Simão e seus companheiros procurá-lo;' },
      { v: 37, en: 'and they found him, and told him, “Everyone is looking for you.”', pt: 'quando o encontraram, disseram-lhe: Todos te buscam.' },
      { v: 38, en: 'He said to them, “Let’s go elsewhere into the next towns, that I may preach there also, because I came out for this reason.”', pt: 'Respondeu-lhes Jesus: Vamos a outras partes, às povoações vizinhas, para que eu pregue ali também; pois para isso é que vim.' },
      { v: 39, en: 'He went into their synagogues throughout all Galilee, preaching and casting out demons.', pt: 'Foi, então, por toda a Galiléia, pregando nas sinagogas deles e expulsando os demônios.' },
      { v: 40, en: 'A leper came to him, begging him, kneeling down to him, and saying to him, “If you want to, you can make me clean.”', pt: 'E veio a ele um leproso que, de joelhos, lhe rogava, dizendo: Se quiseres, bem podes tornar-me limpo.' },
      { v: 41, en: 'Being moved with compassion, he stretched out his hand, and touched him, and said to him, “I want to. Be made clean.”', pt: 'Jesus, pois, compadecido dele, estendendo a mão, tocou-o e disse-lhe: Quero; sê limpo.' },
      { v: 42, en: 'When he had said this, immediately the leprosy departed from him, and he was made clean.', pt: 'Imediatamente desapareceu dele a lepra e ficou limpo.' },
      { v: 43, en: 'He strictly warned him, and immediately sent him out,', pt: 'E Jesus, advertindo-o secretamente, logo o despediu,' },
      { v: 44, en: 'and said to him, “See you say nothing to anybody, but go show yourself to the priest, and offer for your cleansing the things which Moses commanded, for a testimony to them.”', pt: 'dizendo-lhe: Olha, não digas nada a ninguém; mas vai, mostra-te ao sacerdote e oferece pela tua purificação o que Moisés determinou, para lhes servir de testemunho.' },
      { v: 45, en: 'But he went out, and began to proclaim it much, and to spread about the matter, so that Jesus could no more openly enter into a city, but was outside in desert places: and they came to him from everywhere.', pt: 'Ele, porém, saindo dali, começou a publicar o caso por toda parte e a divulgá-lo, de modo que Jesus já não podia entrar abertamente numa cidade, mas conservava-se fora em lugares desertos; e de todos os lados iam ter com ele.' },
    ],
    2: [
      { v: 1, en: 'When he entered again into Capernaum after some days, it was heard that he was in the house.', pt: 'Alguns dias depois entrou Jesus outra vez em Cafarnaum, e soube-se que ele estava em casa.' },
      { v: 2, en: 'Immediately many were gathered together, so that there was no more room, not even around the door; and he spoke the word to them.', pt: 'Ajuntaram-se, pois, muitos, a ponta de não caberem nem mesmo diante da porta; e ele lhes anunciava a palavra.' },
      { v: 3, en: 'Four people came, carrying a paralytic to him.', pt: 'Nisso vieram alguns a trazer-lhe um paralítico, carregado por quatro;' },
      { v: 4, en: 'When they could not come near to him for the crowd, they removed the roof where he was. When they had broken it up, they let down the mat that the paralytic was lying on.', pt: 'e não podendo aproximar-se dele, por causa da multidão, descobriram o telhado onde estava e, fazendo uma abertura, baixaram o leito em que jazia o paralítico.' },
      { v: 5, en: 'Jesus, seeing their faith, said to the paralytic, “Son, your sins are forgiven you.”', pt: 'E Jesus, vendo-lhes a fé, disse ao paralítico: Filho, perdoados são os teus pecados.' },
      { v: 6, en: 'But there were some of the scribes sitting there, and reasoning in their hearts,', pt: 'Ora, estavam ali sentados alguns dos escribas, que arrazoavam em seus corações, dizendo:' },
      { v: 7, en: '“Why does this man speak blasphemies like that? Who can forgive sins but God alone?”', pt: 'Por que fala assim este homem? Ele blasfema. Quem pode perdoar pecados senão um só, que é Deus?' },
      { v: 8, en: 'Immediately Jesus, perceiving in his spirit that they so reasoned within themselves, said to them, “Why do you reason these things in your hearts?', pt: 'Mas Jesus logo percebeu em seu espírito que eles assim arrazoavam dentro de si, e perguntou-lhes: Por que arrazoais desse modo em vossos corações?' },
      { v: 9, en: 'Which is easier, to tell the paralytic, ‘Your sins are forgiven;’ or to say, ‘Arise, and take up your bed, and walk?’', pt: 'Qual é mais fácil? dizer ao paralítico: Perdoados são os teus pecados; ou dizer: Levanta-te, toma o teu leito, e anda?' },
      { v: 10, en: 'But that you may know that the Son of Man has authority on earth to forgive sins” —he said to the paralytic—', pt: 'Ora, para que saibais que o Filho do homem tem sobre a terra autoridade para perdoar pecados ( disse ao paralítico ),' },
      { v: 11, en: '“I tell you, arise, take up your mat, and go to your house.”', pt: 'a ti te digo, levanta-te, toma o teu leito, e vai para tua casa.' },
      { v: 12, en: 'He arose, and immediately took up the mat, and went out in front of them all; so that they were all amazed, and glorified God, saying, “We never saw anything like this!”', pt: 'Então ele se levantou e, tomando logo o leito, saiu à vista de todos; de modo que todos pasmavam e glorificavam a Deus, dizendo: Nunca vimos coisa semelhante.' },
      { v: 13, en: 'He went out again by the seaside. All the multitude came to him, and he taught them.', pt: 'Outra vez saiu Jesus para a beira do mar; e toda a multidão ia ter com ele, e ele os ensinava.' },
      { v: 14, en: 'As he passed by, he saw Levi, the son of Alphaeus, sitting at the tax office, and he said to him, “Follow me.” And he arose and followed him.', pt: 'Quando ia passando, viu a Levi, filho de Alfeu, sentado na coletoria, e disse-lhe: Segue-me. E ele, levantando-se, o seguiu.' },
      { v: 15, en: 'He was reclining at the table in his house, and many tax collectors and sinners sat down with Jesus and his disciples, for there were many, and they followed him.', pt: 'Ora, estando Jesus à mesa em casa de Levi, estavam também ali reclinados com ele e seus discípulos muitos publicanos e pecadores; pois eram em grande número e o seguiam.' },
      { v: 16, en: 'The scribes and the Pharisees, when they saw that he was eating with the sinners and tax collectors, said to his disciples, “Why is it that he eats and drinks with tax collectors and sinners?”', pt: 'Vendo os escribas dos fariseus que comia com os publicanos e pecadores, perguntavam aos discípulos: Por que é que ele como com os publicanos e pecadores?' },
      { v: 17, en: 'When Jesus heard it, he said to them, “Those who are healthy have no need for a physician, but those who are sick. I came not to call the righteous, but sinners to repentance.”', pt: 'Jesus, porém, ouvindo isso, disse-lhes: Não necessitam de médico os sãos, mas sim os enfermos; eu não vim chamar justos, mas pecadores.' },
      { v: 18, en: 'John’s disciples and the Pharisees were fasting, and they came and asked him, “Why do John’s disciples and the disciples of the Pharisees fast, but your disciples don’t fast?”', pt: 'Ora, os discípulos de João e os fariseus estavam jejuando; e foram perguntar-lhe: Por que jejuam os discípulos de João e os dos fariseus, mas os teus discípulos não jejuam?' },
      { v: 19, en: 'Jesus said to them, “Can the groomsmen fast while the bridegroom is with them? As long as they have the bridegroom with them, they can’t fast.', pt: 'Respondeu-lhes Jesus: Podem, porventura, jejuar os convidados às núpcias, enquanto está com eles o noivo? Enquanto têm consigo o noivo não podem jejuar;' },
      { v: 20, en: 'But the days will come when the bridegroom will be taken away from them, and then will they fast in that day.', pt: 'dias virão, porém, em que lhes será tirado o noivo; nesses dias, sim hão de jejuar.' },
      { v: 21, en: 'No one sews a piece of unshrunk cloth on an old garment, or else the patch shrinks and the new tears away from the old, and a worse hole is made.', pt: 'Ninguém cose remendo de pano novo em vestido velho; do contrário o remendo novo tira parte do velho, e torna-se maior a rotura.' },
      { v: 22, en: 'No one puts new wine into old wineskins, or else the new wine will burst the skins, and the wine pours out, and the skins will be destroyed; but they put new wine into fresh wineskins.”', pt: 'E ninguém deita vinho novo em odres velhos; do contrário, o vinho novo romperá os odres, e perder-se-á o vinho e também os odres; mas deita-se vinho novo em odres novos.' },
      { v: 23, en: 'He was going on the Sabbath day through the grain fields, and his disciples began, as they went, to pluck the ears of grain.', pt: 'E sucedeu passar ele num dia de sábado pelas searas; e os seus discípulos, caminhando, começaram a colher espigas.' },
      { v: 24, en: 'The Pharisees said to him, “Behold, why do they do that which is not lawful on the Sabbath day?”', pt: 'E os fariseus lhe perguntaram: Olha, por que estão fazendo no sábado o que não é lícito?' },
      { v: 25, en: 'He said to them, “Did you never read what David did, when he had need, and was hungry—he, and those who were with him?', pt: 'Respondeu-lhes ele: Acaso nunca lestes o que fez Davi quando se viu em necessidade e teve fome, ele e seus companheiros?' },
      { v: 26, en: 'How he entered into God’s house at the time of Abiathar the high priest, and ate the show bread, which is not lawful to eat except for the priests, and gave also to those who were with him?”', pt: 'Como entrou na casa de Deus, no tempo do sumo sacerdote Abiatar, e comeu dos pães da proposição, dos quais não era lícito comer senão aos sacerdotes, e deu também aos companheiros?' },
      { v: 27, en: 'He said to them, “The Sabbath was made for man, not man for the Sabbath.', pt: 'E prosseguiu: O sábado foi feito por causa do homem, e não o homem por causa do sábado.' },
      { v: 28, en: 'Therefore the Son of Man is lord even of the Sabbath.”', pt: 'Pelo que o Filho do homem até do sábado é Senhor.' },
    ],
    3: [
      { v: 1, en: 'He entered again into the synagogue, and there was a man there who had his hand withered.', pt: 'Outra vez entrou numa sinagoga, e estava ali um homem que tinha uma das mãos atrofiada.' },
      { v: 2, en: 'They watched him, whether he would heal him on the Sabbath day, that they might accuse him.', pt: 'E observavam-no para ver se no sábado curaria o homem, a fim de o acusarem.' },
      { v: 3, en: 'He said to the man who had his hand withered, “Stand up.”', pt: 'E disse Jesus ao homem que tinha a mão atrofiada: Levanta-te e vem para o meio.' },
      { v: 4, en: 'He said to them, “Is it lawful on the Sabbath day to do good, or to do harm? To save a life, or to kill?” But they were silent.', pt: 'Então lhes perguntou: É lícito no sábado fazer bem, ou fazer mal? salvar a vida ou matar? Eles, porém, se calaram.' },
      { v: 5, en: 'When he had looked around at them with anger, being grieved at the hardening of their hearts, he said to the man, “Stretch out your hand.” He stretched it out, and his hand was restored as healthy as the other.', pt: 'E olhando em redor para eles com indignação, condoendo-se da dureza dos seus corações, disse ao homem: Estende a tua mão. Ele estendeu, e lhe foi restabelecida.' },
      { v: 6, en: 'The Pharisees went out, and immediately conspired with the Herodians against him, how they might destroy him.', pt: 'E os fariseus, saindo dali, entraram logo em conselho com os herodianos contra ele, para o matarem.' },
      { v: 7, en: 'Jesus withdrew to the sea with his disciples, and a great multitude followed him from Galilee, from Judea,', pt: 'Jesus, porém, se retirou com os seus discípulos para a beira do mar; e uma grande multidão dos da Galiléia o seguiu; também da Judéia,' },
      { v: 8, en: 'from Jerusalem, from Idumaea, beyond the Jordan, and those from around Tyre and Sidon. A great multitude, hearing what great things he did, came to him.', pt: 'e de Jerusalém, da Iduméia e de além do Jordão, e das regiões de Tiro e de Sidom, grandes multidões, ouvindo falar de tudo quanto fazia, vieram ter com ele.' },
      { v: 9, en: 'He spoke to his disciples that a little boat should stay near him because of the crowd, so that they wouldn’t press on him.', pt: 'Recomendou, pois, a seus discípulos que se lhe preparasse um barquinho, por causa da multidão, para que não o apertasse;' },
      { v: 10, en: 'For he had healed many, so that as many as had diseases pressed on him that they might touch him.', pt: 'porque tinha curado a muitos, de modo que todos quantos tinham algum mal arrojavam-se a ele para lhe tocarem.' },
      { v: 11, en: 'The unclean spirits, whenever they saw him, fell down before him, and cried, “You are the Son of God!”', pt: 'E os espíritos imundos, quando o viam, prostravam-se diante dele e clamavam, dizendo: Tu és o Filho de Deus.' },
      { v: 12, en: 'He sternly warned them that they should not make him known.', pt: 'E ele lhes advertia com insistência que não o dessem a conhecer.' },
      { v: 13, en: 'He went up into the mountain, and called to himself those whom he wanted, and they went to him.', pt: 'Depois subiu ao monte, e chamou a si os que ele mesmo queria; e vieram a ele.' },
      { v: 14, en: 'He appointed twelve, that they might be with him, and that he might send them out to preach,', pt: 'Então designou doze para que estivessem com ele, e os mandasse a pregar;' },
      { v: 15, en: 'and to have authority to heal sicknesses and to cast out demons:', pt: 'e para que tivessem autoridade de expulsar os demônios.' },
      { v: 16, en: 'Simon (to whom he gave the name Peter);', pt: 'Designou, pois, os doze, a saber: Simão, a quem pôs o nome de Pedro;' },
      { v: 17, en: 'James the son of Zebedee; and John, the brother of James, (whom he called Boanerges, which means, Sons of Thunder);', pt: 'Tiago, filho de Zebedeu, e João, irmão de Tiago, aos quais pôs o nome de Boanerges, que significa: Filhos do trovão;' },
      { v: 18, en: 'Andrew; Philip; Bartholomew; Matthew; Thomas; James, the son of Alphaeus; Thaddaeus; Simon the Zealot;', pt: 'André, Filipe, Bartolomeu, Mateus, Tomé, Tiago, filho de Alfeu, Tadeu, Simão, o cananeu,' },
      { v: 19, en: 'and Judas Iscariot, who also betrayed him. Then he came into a house.', pt: 'e Judas Iscariotes, aquele que o traiu.' },
      { v: 20, en: 'The multitude came together again, so that they could not so much as eat bread.', pt: 'Depois entrou numa casa. E afluiu outra vez a multidão, de tal modo que nem podiam comer.' },
      { v: 21, en: 'When his friends heard it, they went out to seize him: for they said, “He is insane.”', pt: 'Quando os seus ouviram isso, saíram para o prender; porque diziam: Ele está fora de si.' },
      { v: 22, en: 'The scribes who came down from Jerusalem said, “He has Beelzebul,” and, “By the prince of the demons he casts out the demons.”', pt: 'E os escribas que tinham descido de Jerusalém diziam: Ele está possesso de Belzebu; e: É pelo príncipe dos demônios que expulsa os demônios.' },
      { v: 23, en: 'He summoned them, and said to them in parables, “How can Satan cast out Satan?', pt: 'Então Jesus os chamou e lhes disse por parábolas: Como pode Satanás expulsar Satanás?' },
      { v: 24, en: 'If a kingdom is divided against itself, that kingdom cannot stand.', pt: 'Pois, se um reino se dividir contra si mesmo, tal reino não pode subsistir;' },
      { v: 25, en: 'If a house is divided against itself, that house cannot stand.', pt: 'ou, se uma casa se dividir contra si mesma, tal casa não poderá subsistir;' },
      { v: 26, en: 'If Satan has risen up against himself, and is divided, he can’t stand, but has an end.', pt: 'e se Satanás se tem levantado contra si mesmo, e está dividido, tampouco pode ele subsistir; antes tem fim.' },
      { v: 27, en: 'But no one can enter into the house of the strong man to plunder, unless he first binds the strong man; and then he will plunder his house.', pt: 'Pois ninguém pode entrar na casa do valente e roubar-lhe os bens, se primeiro não amarrar o valente; e então lhe saqueará a casa.' },
      { v: 28, en: 'Most certainly I tell you, all sins of the descendants of man will be forgiven, including their blasphemies with which they may blaspheme;', pt: 'Em verdade vos digo: Todos os pecados serão perdoados aos filhos dos homens, bem como todas as blasfêmias que proferirem;' },
      { v: 29, en: 'but whoever may blaspheme against the Holy Spirit never has forgiveness, but is subject to eternal condemnation.”', pt: 'mas aquele que blasfemar contra o Espírito Santo, nunca mais terá perdão, mas será réu de pecado eterno.' },
      { v: 30, en: '—because they said, “He has an unclean spirit.”', pt: 'Porquanto eles diziam: Está possesso de um espírito imundo.' },
      { v: 31, en: 'His mother and his brothers came, and standing outside, they sent to him, calling him.', pt: 'Chegaram então sua mãe e seus irmãos e, ficando da parte de fora, mandaram chamá-lo.' },
      { v: 32, en: 'A multitude was sitting around him, and they told him, “Behold, your mother, your brothers, and your sisters are outside looking for you.”', pt: 'E a multidão estava sentada ao redor dele, e disseram-lhe: Eis que tua mãe e teus irmãos estão lá fora e te procuram.' },
      { v: 33, en: 'He answered them, “Who are my mother and my brothers?”', pt: 'Respondeu-lhes Jesus, dizendo: Quem é minha mãe e meus irmãos!' },
      { v: 34, en: 'Looking around at those who sat around him, he said, “Behold, my mother and my brothers!', pt: 'E olhando em redor para os que estavam sentados à roda de si, disse: Eis aqui minha mãe e meus irmãos!' },
      { v: 35, en: 'For whoever does the will of God, the same is my brother, and my sister, and mother.”', pt: 'Pois aquele que fizer a vontade de Deus, esse é meu irmão, irmã e mãe.' },
    ],
    4: [
      { v: 1, en: 'Again he began to teach by the seaside. A great multitude was gathered to him, so that he entered into a boat in the sea, and sat down. All the multitude were on the land by the sea.', pt: 'Outra vez começou a ensinar à beira do mar. E reuniu-se a ele tão grande multidão que ele entrou num barco e sentou-se nele, sobre o mar; e todo o povo estava em terra junto do mar.' },
      { v: 2, en: 'He taught them many things in parables, and told them in his teaching,', pt: 'Então lhes ensinava muitas coisas por parábolas, e lhes dizia no seu ensino:' },
      { v: 3, en: '“Listen! Behold, the farmer went out to sow,', pt: 'Ouvi: Eis que o semeador saiu a semear;' },
      { v: 4, en: 'and as he sowed, some seed fell by the road, and the birds came and devoured it.', pt: 'e aconteceu que, quando semeava, uma parte da semente caiu à beira do caminho, e vieram as aves e a comeram.' },
      { v: 5, en: 'Others fell on the rocky ground, where it had little soil, and immediately it sprang up, because it had no depth of soil.', pt: 'Outra caiu no solo pedregoso, onde não havia muita terra: e logo nasceu, porque não tinha terra profunda;' },
      { v: 6, en: 'When the sun had risen, it was scorched; and because it had no root, it withered away.', pt: 'mas, saindo o sol, queimou-se; e, porque não tinha raiz, secou-se.' },
      { v: 7, en: 'Others fell among the thorns, and the thorns grew up, and choked it, and it yielded no fruit.', pt: 'E outra caiu entre espinhos; e cresceram os espinhos, e a sufocaram; e não deu fruto.' },
      { v: 8, en: 'Others fell into the good ground, and yielded fruit, growing up and increasing. Some produced thirty times, some sixty times, and some one hundred times as much.”', pt: 'Mas outras caíram em boa terra e, vingando e crescendo, davam fruto; e um grão produzia trinta, outro sessenta, e outro cem.' },
      { v: 9, en: 'He said, “Whoever has ears to hear, let him hear.”', pt: 'E disse-lhes: Quem tem ouvidos para ouvir, ouça.' },
      { v: 10, en: 'When he was alone, those who were around him with the twelve asked him about the parables.', pt: 'Quando se achou só, os que estavam ao redor dele, com os doze, interrogaram-no acerca da parábola.' },
      { v: 11, en: 'He said to them, “To you is given the mystery of God’s Kingdom, but to those who are outside, all things are done in parables,', pt: 'E ele lhes disse: A vós é confiado o mistério do reino de Deus, mas aos de fora tudo se lhes diz por parábolas;' },
      { v: 12, en: 'that ‘seeing they may see, and not perceive; and hearing they may hear, and not understand; lest perhaps they should turn again, and their sins should be forgiven them.’”', pt: 'para que vendo, vejam, e não percebam; e ouvindo, ouçam, e não entendam; para que não se convertam e sejam perdoados.' },
      { v: 13, en: 'He said to them, “Don’t you understand this parable? How will you understand all of the parables?', pt: 'Disse-lhes ainda: Não percebeis esta parábola? como pois entendereis todas as parábolas?' },
      { v: 14, en: 'The farmer sows the word.', pt: 'O semeador semeia a palavra.' },
      { v: 15, en: 'The ones by the road are the ones where the word is sown; and when they have heard, immediately Satan comes, and takes away the word which has been sown in them.', pt: 'E os que estão junto do caminho são aqueles em quem a palavra é semeada; mas, tendo-a eles ouvido, vem logo Satanás e tira a palavra que neles foi semeada.' },
      { v: 16, en: 'These in the same way are those who are sown on the rocky places, who, when they have heard the word, immediately receive it with joy.', pt: 'Do mesmo modo, aqueles que foram semeados nos lugares pedregosos são os que, ouvindo a palavra, imediatamente com alegria a recebem;' },
      { v: 17, en: 'They have no root in themselves, but are short-lived. When oppression or persecution arises because of the word, immediately they stumble.', pt: 'mas não têm raiz em si mesmos, antes são de pouca duração; depois, sobrevindo tribulação ou perseguição por causa da palavra, logo se escandalizam.' },
      { v: 18, en: 'Others are those who are sown among the thorns. These are those who have heard the word,', pt: 'Outros ainda são aqueles que foram semeados entre os espinhos; estes são os que ouvem a palavra;' },
      { v: 19, en: 'and the cares of this age, and the deceitfulness of riches, and the lusts of other things entering in choke the word, and it becomes unfruitful.', pt: 'mas os cuidados do mundo, a sedução das riquezas e a cobiça doutras coisas, entrando, sufocam a palavra, e ela fica infrutífera.' },
      { v: 20, en: 'Those which were sown on the good ground are those who hear the word, and accept it, and bear fruit, some thirty times, some sixty times, and some one hundred times.”', pt: 'Aqueles outros que foram semeados em boa terra são os que ouvem a palavra e a recebem, e dão fruto, a trinta, a sessenta, e a cem, por um.' },
      { v: 21, en: 'He said to them, “Is the lamp brought to be put under a basket or under a bed? Isn’t it put on a stand?', pt: 'Disse-lhes mais: Vem porventura a candeia para se meter debaixo do alqueire, ou debaixo da cama? não é antes para se colocar no velador?' },
      { v: 22, en: 'For there is nothing hidden, except that it should be made known; neither was anything made secret, but that it should come to light.', pt: 'Porque nada está encoberto senão para ser manifesto; e nada foi escondido senão para vir à luz.' },
      { v: 23, en: 'If any man has ears to hear, let him hear.”', pt: 'Se alguém tem ouvidos para ouvir, ouça.' },
      { v: 24, en: 'He said to them, “Take heed what you hear. With whatever measure you measure, it will be measured to you, and more will be given to you who hear.', pt: 'Também lhes disse: Atendei ao que ouvis. Com a medida com que medis vos medirão a vós, e ainda se vos acrescentará.' },
      { v: 25, en: 'For whoever has, to him will more be given, and he who doesn’t have, even that which he has will be taken away from him.”', pt: 'Pois ao que tem, ser-lhe-á dado; e ao que não tem, até aquilo que tem ser-lhe-á tirado.' },
      { v: 26, en: 'He said, “God’s Kingdom is as if a man should cast seed on the earth,', pt: 'Disse também: O reino de Deus é assim como se um homem lançasse semente à terra,' },
      { v: 27, en: 'and should sleep and rise night and day, and the seed should spring up and grow, though he doesn’t know how.', pt: 'e dormisse e se levantasse de noite e de dia, e a semente brotasse e crescesse, sem ele saber como.' },
      { v: 28, en: 'For the earth bears fruit: first the blade, then the ear, then the full grain in the ear.', pt: 'A terra por si mesma produz fruto, primeiro a erva, depois a espiga, e por último o grão cheio na espiga.' },
      { v: 29, en: 'But when the fruit is ripe, immediately he puts in the sickle, because the harvest has come.”', pt: 'Mas assim que o fruto amadurecer, logo lhe mete a foice, porque é chegada a ceifa.' },
      { v: 30, en: 'He said, “How will we liken God’s Kingdom? Or with what parable will we illustrate it?', pt: 'Disse ainda: A que assemelharemos o reino de Deus? ou com que parábola o representaremos?' },
      { v: 31, en: 'It’s like a grain of mustard seed, which, when it is sown in the earth, though it is less than all the seeds that are on the earth,', pt: 'É como um grão de mostarda que, quando se semeia, é a menor de todas as sementes que há na terra;' },
      { v: 32, en: 'yet when it is sown, grows up, and becomes greater than all the herbs, and puts out great branches, so that the birds of the sky can lodge under its shadow.”', pt: 'mas, tendo sido semeado, cresce e faz-se a maior de todas as hortaliças e cria grandes ramos, de tal modo que as aves do céu podem aninhar-se à sua sombra.' },
      { v: 33, en: 'With many such parables he spoke the word to them, as they were able to hear it.', pt: 'E com muitas parábolas tais lhes dirigia a palavra, conforme podiam compreender.' },
      { v: 34, en: 'Without a parable he didn’t speak to them; but privately to his own disciples he explained everything.', pt: 'E sem parábola não lhes falava; mas em particular explicava tudo a seus discípulos.' },
      { v: 35, en: 'On that day, when evening had come, he said to them, “Let’s go over to the other side.”', pt: 'Naquele dia, quando já era tarde, disse-lhes: Passemos para o outro lado.' },
      { v: 36, en: 'Leaving the multitude, they took him with them, even as he was, in the boat. Other small boats were also with him.', pt: 'E eles, deixando a multidão, o levaram consigo, assim como estava, no barco; e havia com ele também outros barcos.' },
      { v: 37, en: 'A big wind storm arose, and the waves beat into the boat, so much that the boat was already filled.', pt: 'E se levantou grande tempestade de vento, e as ondas batiam dentro do barco, de modo que já se enchia.' },
      { v: 38, en: 'He himself was in the stern, asleep on the cushion, and they woke him up, and told him, “Teacher, don’t you care that we are dying?”', pt: 'Ele, porém, estava na popa dormindo sobre a almofada; e despertaram-no, e lhe perguntaram: Mestre, não se te dá que pereçamos?' },
      { v: 39, en: 'He awoke, and rebuked the wind, and said to the sea, “Peace! Be still!” The wind ceased, and there was a great calm.', pt: 'E ele, levantando-se, repreendeu o vento, e disse ao mar: Cala-te, aquieta-te. E cessou o vento, e fez-se grande bonança.' },
      { v: 40, en: 'He said to them, “Why are you so afraid? How is it that you have no faith?”', pt: 'Então lhes perguntou: Por que sois assim tímidos? Ainda não tendes fé?' },
      { v: 41, en: 'They were greatly afraid, and said to one another, “Who then is this, that even the wind and the sea obey him?”', pt: 'Encheram-se de grande temor, e diziam uns aos outros: Quem, porventura, é este, que até o vento e o mar lhe obedecem?' },
    ],
    5: [
      { v: 1, en: 'They came to the other side of the sea, into the country of the Gadarenes.', pt: 'Chegaram então ao outro lado do mar, à terra dos gerasenos.' },
      { v: 2, en: 'When he had come out of the boat, immediately a man with an unclean spirit met him out of the tombs.', pt: 'E, logo que Jesus saíra do barco, lhe veio ao encontro, dos sepulcros, um homem com espírito imundo,' },
      { v: 3, en: 'He lived in the tombs. Nobody could bind him any more, not even with chains,', pt: 'o qual tinha a sua morada nos sepulcros; e nem ainda com cadeias podia alguém prendê-lo;' },
      { v: 4, en: 'because he had been often bound with fetters and chains, and the chains had been torn apart by him, and the fetters broken in pieces. Nobody had the strength to tame him.', pt: 'porque, tendo sido muitas vezes preso com grilhões e cadeias, as cadeias foram por ele feitas em pedaços, e os grilhões em migalhas; e ninguém o podia domar;' },
      { v: 5, en: 'Always, night and day, in the tombs and in the mountains, he was crying out, and cutting himself with stones.', pt: 'e sempre, de dia e de noite, andava pelos sepulcros e pelos montes, gritando, e ferindo-se com pedras,' },
      { v: 6, en: 'When he saw Jesus from afar, he ran and bowed down to him,', pt: 'Vendo, pois, de longe a Jesus, correu e adorou-o;' },
      { v: 7, en: 'and crying out with a loud voice, he said, “What have I to do with you, Jesus, you Son of the Most High God? I adjure you by God, don’t torment me.”', pt: 'e, clamando com grande voz, disse: Que tenho eu contigo, Jesus, Filho do Deus Altíssimo? conjuro-te por Deus que não me atormentes.' },
      { v: 8, en: 'For he said to him, “Come out of the man, you unclean spirit!”', pt: 'Pois Jesus lhe dizia: Sai desse homem, espírito imundo.' },
      { v: 9, en: 'He asked him, “What is your name?” He said to him, “My name is Legion, for we are many.”', pt: 'E perguntou-lhe: Qual é o teu nome? Respondeu-lhe ele: Legião é o meu nome, porque somos muitos.' },
      { v: 10, en: 'He begged him much that he would not send them away out of the country.', pt: 'E rogava-lhe muito que não os enviasse para fora da região.' },
      { v: 11, en: 'Now on the mountainside there was a great herd of pigs feeding.', pt: 'Ora, andava ali pastando no monte uma grande manada de porcos.' },
      { v: 12, en: 'All the demons begged him, saying, “Send us into the pigs, that we may enter into them.”', pt: 'Rogaram-lhe, pois, os demônios, dizendo: Manda-nos para aqueles porcos, para que entremos neles.' },
      { v: 13, en: 'At once Jesus gave them permission. The unclean spirits came out and entered into the pigs. The herd of about two thousand rushed down the steep bank into the sea, and they were drowned in the sea.', pt: 'E ele lho permitiu. Saindo, então, os espíritos imundos, entraram nos porcos; e precipitou-se a manada, que era de uns dois mil, pelo despenhadeiro no mar, onde todos se afogaram.' },
      { v: 14, en: 'Those who fed them fled, and told it in the city and in the country. The people came to see what it was that had happened.', pt: 'Nisso fugiram aqueles que os apascentavam, e o anunciaram na cidade e nos campos; e muitos foram ver o que era aquilo que tinha acontecido.' },
      { v: 15, en: 'They came to Jesus, and saw him who had been possessed by demons sitting, clothed, and in his right mind, even him who had the legion; and they were afraid.', pt: 'Chegando-se a Jesus, viram o endemoninhado, o que tivera a legião, sentado, vestido, e em perfeito juízo; e temeram.' },
      { v: 16, en: 'Those who saw it declared to them what happened to him who was possessed by demons, and about the pigs.', pt: 'E os que tinham visto aquilo contaram-lhes como havia acontecido ao endemoninhado, e acerca dos porcos.' },
      { v: 17, en: 'They began to beg him to depart from their region.', pt: 'Então começaram a rogar-lhe que se retirasse dos seus termos.' },
      { v: 18, en: 'As he was entering into the boat, he who had been possessed by demons begged him that he might be with him.', pt: 'E, entrando ele no barco, rogava-lhe o que fora endemoninhado que o deixasse estar com ele.' },
      { v: 19, en: 'He didn’t allow him, but said to him, “Go to your house, to your friends, and tell them what great things the Lord has done for you, and how he had mercy on you.”', pt: 'Jesus, porém, não lho permitiu, mas disse-lhe: Vai para tua casa, para os teus, e anuncia-lhes o quanto o Senhor te fez, e como teve misericórdia de ti.' },
      { v: 20, en: 'He went his way, and began to proclaim in Decapolis how Jesus had done great things for him, and everyone marveled.', pt: 'Ele se retirou, pois, e começou a publicar em Decápolis tudo quanto lhe fizera Jesus; e todos se admiravam.' },
      { v: 21, en: 'When Jesus had crossed back over in the boat to the other side, a great multitude was gathered to him; and he was by the sea.', pt: 'Tendo Jesus passado de novo no barco para o outro lado, ajuntou-se a ele uma grande multidão; e ele estava à beira do mar.' },
      { v: 22, en: 'Behold, one of the rulers of the synagogue, Jairus by name, came; and seeing him, he fell at his feet,', pt: 'Chegou um dos chefes da sinagoga, chamado Jairo e, logo que viu a Jesus, lançou-se-lhe aos pés.' },
      { v: 23, en: 'and begged him much, saying, “My little daughter is at the point of death. Please come and lay your hands on her, that she may be made healthy, and live.”', pt: 'e lhe rogava com instância, dizendo: Minha filhinha está nas últimas; rogo-te que venhas e lhe imponhas as mãos para que sare e viva.' },
      { v: 24, en: 'He went with him, and a great multitude followed him, and they pressed upon him on all sides.', pt: 'Jesus foi com ele, e seguia-o uma grande multidão, que o apertava.' },
      { v: 25, en: 'A certain woman, who had an issue of blood for twelve years,', pt: 'Ora, certa mulher, que havia doze anos padecia de uma hemorragia,' },
      { v: 26, en: 'and had suffered many things by many physicians, and had spent all that she had, and was no better, but rather grew worse,', pt: 'e que tinha sofrido bastante às mãos de muitos médicos, e despendido tudo quanto possuía sem nada aproveitar, antes indo a pior,' },
      { v: 27, en: 'having heard the things concerning Jesus, came up behind him in the crowd, and touched his clothes.', pt: 'tendo ouvido falar a respeito de Jesus, veio por detrás, entre a multidão, e tocou-lhe o manto;' },
      { v: 28, en: 'For she said, “If I just touch his clothes, I will be made well.”', pt: 'porque dizia: Se tão-somente tocar-lhe as vestes, ficaria curada.' },
      { v: 29, en: 'Immediately the flow of her blood was dried up, and she felt in her body that she was healed of her affliction.', pt: 'E imediatamente cessou a sua hemorragia; e sentiu no corpo estar já curada do seu mal.' },
      { v: 30, en: 'Immediately Jesus, perceiving in himself that the power had gone out from him, turned around in the crowd, and asked, “Who touched my clothes?”', pt: 'E logo Jesus, percebendo em si mesmo que saíra dele poder, virou-se no meio da multidão e perguntou: Quem me tocou as vestes?' },
      { v: 31, en: 'His disciples said to him, “You see the multitude pressing against you, and you say, ‘Who touched me?’”', pt: 'Responderam-lhe os seus discípulos: Vês que a multidão te aperta, e perguntas: Quem me tocou?' },
      { v: 32, en: 'He looked around to see her who had done this thing.', pt: 'Mas ele olhava em redor para ver a que isto fizera.' },
      { v: 33, en: 'But the woman, fearing and trembling, knowing what had been done to her, came and fell down before him, and told him all the truth.', pt: 'Então a mulher, atemorizada e trêmula, cônscia do que nela se havia operado, veio e prostrou-se diante dele, e declarou-lhe toda a verdade.' },
      { v: 34, en: 'He said to her, “Daughter, your faith has made you well. Go in peace, and be cured of your disease.”', pt: 'Disse-lhe ele: Filha, a tua fé te salvou; vai-te em paz, e fica livre desse teu mal.' },
      { v: 35, en: 'While he was still speaking, people came from the synagogue ruler’s house saying, “Your daughter is dead. Why bother the Teacher any more?”', pt: 'Enquanto ele ainda falava, chegaram pessoas da casa do chefe da sinagoga, a quem disseram: A tua filha já morreu; por que ainda incomodas o Mestre?' },
      { v: 36, en: 'But Jesus, when he heard the message spoken, immediately said to the ruler of the synagogue, “Don’t be afraid, only believe.”', pt: 'O que percebendo Jesus, disse ao chefe da sinagoga: Não temas, crê somente.' },
      { v: 37, en: 'He allowed no one to follow him, except Peter, James, and John the brother of James.', pt: 'E não permitiu que ninguém o acompanhasse, senão Pedro, Tiago, e João, irmão de Tiago.' },
      { v: 38, en: 'He came to the synagogue ruler’s house, and he saw an uproar, weeping, and great wailing.', pt: 'Quando chegaram a casa do chefe da sinagoga, viu Jesus um alvoroço, e os que choravam e faziam grande pranto.' },
      { v: 39, en: 'When he had entered in, he said to them, “Why do you make an uproar and weep? The child is not dead, but is asleep.”', pt: 'E, entrando, disse-lhes: Por que fazeis alvoroço e chorais? a menina não morreu, mas dorme.' },
      { v: 40, en: 'They ridiculed him. But he, having put them all out, took the father of the child, her mother, and those who were with him, and went in where the child was lying.', pt: 'E riam-se dele; porém ele, tendo feito sair a todos, tomou consigo o pai e a mãe da menina, e os que com ele vieram, e entrou onde a menina estava.' },
      { v: 41, en: 'Taking the child by the hand, he said to her, “Talitha cumi!” which means, being interpreted, “Girl, I tell you, get up!”', pt: 'E, tomando a mão da menina, disse-lhe: Talita cumi, que, traduzido, é: Menina, a ti te digo, levanta-te.' },
      { v: 42, en: 'Immediately the girl rose up and walked, for she was twelve years old. They were amazed with great amazement.', pt: 'Imediatamente a menina se levantou, e pôs-se a andar, pois tinha doze anos. E logo foram tomados de grande espanto.' },
      { v: 43, en: 'He strictly ordered them that no one should know this, and commanded that something should be given to her to eat.', pt: 'Então ordenou-lhes expressamente que ninguém o soubesse; e mandou que lhe dessem de comer.' },
    ],
    6: [
      { v: 1, en: 'He went out from there. He came into his own country, and his disciples followed him.', pt: 'Saiu Jesus dali, e foi para a sua terra, e os seus discípulos o seguiam.' },
      { v: 2, en: 'When the Sabbath had come, he began to teach in the synagogue, and many hearing him were astonished, saying, “Where did this man get these things?” and, “What is the wisdom that is given to this man, that such mighty works come about by his hands?', pt: 'Ora, chegando o sábado, começou a ensinar na sinagoga; e muitos, ao ouví-lo, se maravilhavam, dizendo: Donde lhe vêm estas coisas? e que sabedoria é esta que lhe é dada? e como se fazem tais milagres por suas mãos?' },
      { v: 3, en: 'Isn’t this the carpenter, the son of Mary, and brother of James, Joses, Judah, and Simon? Aren’t his sisters here with us?” They were offended at him.', pt: 'Não é este o carpinteiro, filho de Maria, irmão de Tiago, de José, de Judas e de Simão? e não estão aqui entre nós suas irmãs? E escandalizavam-se dele.' },
      { v: 4, en: 'Jesus said to them, “A prophet is not without honor, except in his own country, and among his own relatives, and in his own house.”', pt: 'Então Jesus lhes dizia: Um profeta não fica sem honra senão na sua terra, entre os seus parentes, e na sua própria casa.' },
      { v: 5, en: 'He could do no mighty work there, except that he laid his hands on a few sick people, and healed them.', pt: 'E não podia fazer ali nenhum milagre, a não ser curar alguns poucos enfermos, impondo-lhes as mãos.' },
      { v: 6, en: 'He marveled because of their unbelief. He went around the villages teaching.', pt: 'E admirou-se da incredulidade deles. Em seguida percorria as aldeias circunvizinhas, ensinando.' },
      { v: 7, en: 'He called to himself the twelve, and began to send them out two by two; and he gave them authority over the unclean spirits.', pt: 'E chamou a si os doze, e começou a enviá-los a dois e dois, e dava-lhes poder sobre os espíritos imundos;' },
      { v: 8, en: 'He commanded them that they should take nothing for their journey, except a staff only: no bread, no wallet, no money in their purse,', pt: 'ordenou-lhes que nada levassem para o caminho, senão apenas um bordão; nem pão, nem alforje, nem dinheiro no cinto;' },
      { v: 9, en: 'but to wear sandals, and not put on two tunics.', pt: 'mas que fossem calçados de sandálias, e que não vestissem duas túnicas.' },
      { v: 10, en: 'He said to them, “Wherever you enter into a house, stay there until you depart from there.', pt: 'Dizia-lhes mais: Onde quer que entrardes numa casa, ficai nela até sairdes daquele lugar.' },
      { v: 11, en: 'Whoever will not receive you nor hear you, as you depart from there, shake off the dust that is under your feet for a testimony against them. Assuredly, I tell you, it will be more tolerable for Sodom and Gomorrah in the day of judgment than for that city!”', pt: 'E se qualquer lugar não vos receber, nem os homens vos ouvirem, saindo dali, sacudi o pó que estiver debaixo dos vossos pés, em testemunho contra eles.' },
      { v: 12, en: 'They went out and preached that people should repent.', pt: 'Então saíram e pregaram que todos se arrependessem;' },
      { v: 13, en: 'They cast out many demons, and anointed many with oil who were sick, and healed them.', pt: 'e expulsavam muitos demônios, e ungiam muitos enfermos com óleo, e os curavam.' },
      { v: 14, en: 'King Herod heard this, for his name had become known, and he said, “John the Baptizer has risen from the dead, and therefore these powers are at work in him.”', pt: 'E soube disso o rei Herodes (porque o nome de Jesus se tornara célebre), e disse: João, o Batista, ressuscitou dos mortos; e por isso estes poderes milagrosos operam nele.' },
      { v: 15, en: 'But others said, “He is Elijah.” Others said, “He is a prophet, or like one of the prophets.”', pt: 'Mas outros diziam: É Elias. E ainda outros diziam: É profeta como um dos profetas.' },
      { v: 16, en: 'But Herod, when he heard this, said, “This is John, whom I beheaded. He has risen from the dead.”', pt: 'Herodes, porém, ouvindo isso, dizia: É João, aquele a quem eu mandei degolar: ele ressuscitou.' },
      { v: 17, en: 'For Herod himself had sent out and arrested John, and bound him in prison for the sake of Herodias, his brother Philip’s wife, for he had married her.', pt: 'Porquanto o próprio Herodes mandara prender a João, e encerrá-lo maniatado no cárcere, por causa de Herodias, mulher de seu irmão Filipe; porque ele se havia casado com ela.' },
      { v: 18, en: 'For John said to Herod, “It is not lawful for you to have your brother’s wife.”', pt: 'Pois João dizia a Herodes: Não te é lícito ter a mulher de teu irmão.' },
      { v: 19, en: 'Herodias set herself against him, and desired to kill him, but she couldn’t,', pt: 'Por isso Herodias lhe guardava rancor e queria matá-lo, mas não podia;' },
      { v: 20, en: 'for Herod feared John, knowing that he was a righteous and holy man, and kept him safe. When he heard him, he did many things, and he heard him gladly.', pt: 'porque Herodes temia a João, sabendo que era varão justo e santo, e o guardava em segurança; e, ao ouvi-lo, ficava muito perplexo, contudo de boa mente o escutava.' },
      { v: 21, en: 'Then a convenient day came, that Herod on his birthday made a supper for his nobles, the high officers, and the chief men of Galilee.', pt: 'Chegado, porém, um dia oportuno quando Herodes no seu aniversário natalício ofereceu um banquete aos grandes da sua corte, aos principais da Galiléia,' },
      { v: 22, en: 'When the daughter of Herodias herself came in and danced, she pleased Herod and those sitting with him. The king said to the young lady, “Ask me whatever you want, and I will give it to you.”', pt: 'entrou a filha da mesma Herodias e, dançando, agradou a Herodes e aos convivas. Então o rei disse à jovem: Pede-me o que quiseres, e eu to darei.' },
      { v: 23, en: 'He swore to her, “Whatever you shall ask of me, I will give you, up to half of my kingdom.”', pt: 'E jurou-lhe, dizendo: Tudo o que me pedires te darei, ainda que seja metade do meu reino.' },
      { v: 24, en: 'She went out, and said to her mother, “What shall I ask?” She said, “The head of John the Baptizer.”', pt: 'Tendo ela saído, perguntou a sua mãe: Que pedirei? Ela respondeu: A cabeça de João, o Batista.' },
      { v: 25, en: 'She came in immediately with haste to the king, and asked, “I want you to give me right now the head of John the Baptizer on a platter.”', pt: 'E tornando logo com pressa à presença do rei, pediu, dizendo: Quero que imediatamente me dês num prato a cabeça de João, o Batista.' },
      { v: 26, en: 'The king was exceedingly sorry, but for the sake of his oaths, and of his dinner guests, he didn’t wish to refuse her.', pt: 'Ora, entristeceu-se muito o rei; todavia, por causa dos seus juramentos e por causa dos que estavam à mesa, não lha quis negar.' },
      { v: 27, en: 'Immediately the king sent out a soldier of his guard, and commanded to bring John’s head, and he went and beheaded him in the prison,', pt: 'O rei, pois, enviou logo um soldado da sua guarda com ordem de trazer a cabeça de João. Então ele foi e o degolou no cárcere,' },
      { v: 28, en: 'and brought his head on a platter, and gave it to the young lady; and the young lady gave it to her mother.', pt: 'e trouxe a cabeça num prato e a deu à jovem, e a jovem a deu à sua mãe.' },
      { v: 29, en: 'When his disciples heard this, they came and took up his corpse, and laid it in a tomb.', pt: 'Quando os seus discípulos ouviram isso, vieram, tomaram o seu corpo e o puseram num sepulcro.' },
      { v: 30, en: 'The apostles gathered themselves together to Jesus, and they told him all things, whatever they had done, and whatever they had taught.', pt: 'Reuniram-se os apóstolos com Jesus e contaram-lhe tudo o que tinham feito e ensinado.' },
      { v: 31, en: 'He said to them, “You come apart into a deserted place, and rest awhile.” For there were many coming and going, and they had no leisure so much as to eat.', pt: 'Ao que ele lhes disse: Vinde vós, à parte, para um lugar deserto, e descansai um pouco. Porque eram muitos os que vinham e iam, e não tinham tempo nem para comer.' },
      { v: 32, en: 'They went away in the boat to a deserted place by themselves.', pt: 'Retiraram-se, pois, no barco para um lugar deserto, à parte.' },
      { v: 33, en: 'They saw them going, and many recognized him and ran there on foot from all the cities. They arrived before them and came together to him.', pt: 'Muitos, porém, os viram partir, e os reconheceram; e para lá correram a pé de todas as cidades, e ali chegaram primeiro do que eles.' },
      { v: 34, en: 'Jesus came out, saw a great multitude, and he had compassion on them, because they were like sheep without a shepherd, and he began to teach them many things.', pt: 'E Jesus, ao desembarcar, viu uma grande multidão e compadeceu-se deles, porque eram como ovelhas que não têm pastor; e começou a ensinar-lhes muitas coisas.' },
      { v: 35, en: 'When it was late in the day, his disciples came to him, and said, “This place is deserted, and it is late in the day.', pt: 'Estando a hora já muito adiantada, aproximaram-se dele seus discípulos e disseram: O lugar é deserto, e a hora já está muito adiantada;' },
      { v: 36, en: 'Send them away, that they may go into the surrounding country and villages, and buy themselves bread, for they have nothing to eat.”', pt: 'despede-os, para que vão aos sítios e às aldeias, em redor, e comprem para si o que comer.' },
      { v: 37, en: 'But he answered them, “You give them something to eat.” They asked him, “Shall we go and buy two hundred denarii worth of bread, and give them something to eat?”', pt: 'Ele, porém, lhes respondeu: Dai-lhes vós de comer. Então eles lhe perguntaram: Havemos de ir comprar duzentos denários de pão e dar-lhes de comer?' },
      { v: 38, en: 'He said to them, “How many loaves do you have? Go see.” When they knew, they said, “Five, and two fish.”', pt: 'Ao que ele lhes disse: Quantos pães tendes? Ide ver. E, tendo-se informado, responderam: Cinco pães e dois peixes.' },
      { v: 39, en: 'He commanded them that everyone should sit down in groups on the green grass.', pt: 'Então lhes ordenou que a todos fizessem reclinar-se, em grupos, sobre a relva verde.' },
      { v: 40, en: 'They sat down in ranks, by hundreds and by fifties.', pt: 'E reclinaram-se em grupos de cem e de cinquenta.' },
      { v: 41, en: 'He took the five loaves and the two fish, and looking up to heaven, he blessed and broke the loaves, and he gave to his disciples to set before them, and he divided the two fish among them all.', pt: 'E tomando os cinco pães e os dois peixes, e erguendo os olhos ao céu, os abençoou; partiu os pães e os entregava a seus discípulos para lhos servirem; também repartiu os dois peixes por todos.' },
      { v: 42, en: 'They all ate, and were filled.', pt: 'E todos comeram e se fartaram.' },
      { v: 43, en: 'They took up twelve baskets full of broken pieces and also of the fish.', pt: 'Em seguida, recolheram doze cestos cheios dos pedaços de pão e de peixe.' },
      { v: 44, en: 'Those who ate the loaves were five thousand men.', pt: 'Ora, os que comeram os pães eram cinco mil homens.' },
      { v: 45, en: 'Immediately he made his disciples get into the boat, and to go ahead to the other side, to Bethsaida, while he himself sent the multitude away.', pt: 'Logo em seguida obrigou os seus discípulos a entrar no barco e passar adiante, para o outro lado, a Betsaida, enquanto ele despedia a multidão.' },
      { v: 46, en: 'After he had taken leave of them, he went up the mountain to pray.', pt: 'E, tendo-a despedido, foi ao monte para orar.' },
      { v: 47, en: 'When evening had come, the boat was in the middle of the sea, and he was alone on the land.', pt: 'Chegada a tardinha, estava o barco no meio do mar, e ele sozinho em terra.' },
      { v: 48, en: 'Seeing them distressed in rowing, for the wind was contrary to them, about the fourth watch of the night he came to them, walking on the sea, and he would have passed by them,', pt: 'E, vendo-os fatigados a remar, porque o vento lhes era contrário, pela quarta vigília da noite, foi ter com eles, andando sobre o mar; e queria passar-lhes adiante;' },
      { v: 49, en: 'but they, when they saw him walking on the sea, supposed that it was a ghost, and cried out;', pt: 'eles, porém, ao vê-lo andando sobre o mar, pensaram que era um fantasma e gritaram;' },
      { v: 50, en: 'for they all saw him, and were troubled. But he immediately spoke with them, and said to them, “Cheer up! It is I! Don’t be afraid.”', pt: 'porque todos o viram e se assustaram; mas ele imediatamente falou com eles e disse-lhes: Tende ânimo; sou eu; não temais.' },
      { v: 51, en: 'He got into the boat with them; and the wind ceased, and they were very amazed among themselves, and marveled;', pt: 'E subiu para junto deles no barco, e o vento cessou; e ficaram, no seu íntimo, grandemente pasmados;' },
      { v: 52, en: 'for they hadn’t understood about the loaves, but their hearts were hardened.', pt: 'pois não tinham compreendido o milagre dos pães, antes o seu coração estava endurecido.' },
      { v: 53, en: 'When they had crossed over, they came to land at Gennesaret, and moored to the shore.', pt: 'E, terminada a travessia, chegaram à terra em Genezaré, e ali atracaram.' },
      { v: 54, en: 'When they had come out of the boat, immediately the people recognized him,', pt: 'Logo que desembarcaram, o povo reconheceu a Jesus;' },
      { v: 55, en: 'and ran around that whole region, and began to bring those who were sick, on their mats, to where they heard he was.', pt: 'e correndo eles por toda aquela região, começaram a levar nos leitos os que se achavam enfermos, para onde ouviam dizer que ele estava.' },
      { v: 56, en: 'Wherever he entered, into villages, or into cities, or into the country, they laid the sick in the marketplaces, and begged him that they might just touch the fringe of his garment; and as many as touched him were made well.', pt: 'Onde quer, pois, que entrava, fosse nas aldeias, nas cidades ou nos campos, apresentavam os enfermos nas praças, e rogavam-lhe que os deixasse tocar ao menos a orla do seu manto; e todos os que a tocavam ficavam curados.' },
    ],
    7: [
      { v: 1, en: 'Then the Pharisees and some of the scribes gathered together to him, having come from Jerusalem.', pt: 'Foram ter com Jesus os fariseus, e alguns dos escribas vindos de Jerusalém,' },
      { v: 2, en: 'Now when they saw some of his disciples eating bread with defiled, that is unwashed, hands, they found fault.', pt: 'e repararam que alguns dos seus discípulos comiam pão com as mãos impuras, isto é, por lavar.' },
      { v: 3, en: '(For the Pharisees and all the Jews, don’t eat unless they wash their hands and forearms, holding to the tradition of the elders.', pt: 'Pois os fariseus, e todos os judeus, guardando a tradição dos anciãos, não comem sem lavar as mãos cuidadosamente;' },
      { v: 4, en: 'They don’t eat when they come from the marketplace unless they bathe themselves, and there are many other things, which they have received to hold to: washings of cups, pitchers, bronze vessels, and couches.)', pt: 'e quando voltam do mercado, se não se purificarem, não comem. E muitas outras coisas há que receberam para observar, como a lavagem de copos, de jarros e de vasos de bronze.' },
      { v: 5, en: 'The Pharisees and the scribes asked him, “Why don’t your disciples walk according to the tradition of the elders, but eat their bread with unwashed hands?”', pt: 'Perguntaram-lhe, pois, os fariseus e os escribas: Por que não andam os teus discípulos conforme a tradição dos anciãos, mas comem o pão com as mãos por lavar?' },
      { v: 6, en: 'He answered them, “Well did Isaiah prophesy of you hypocrites, as it is written, ‘This people honors me with their lips, but their heart is far from me.', pt: 'Respondeu-lhes: Bem profetizou Isaías acerca de vós, hipócritas, como está escrito: Este povo honra-me com os lábios; o seu coração, porém, está longe de mim;' },
      { v: 7, en: 'But they worship me in vain, teaching as doctrines the commandments of men.’', pt: 'mas em vão me adoram, ensinando doutrinas que são preceitos de homens.' },
      { v: 8, en: '“For you set aside the commandment of God, and hold tightly to the tradition of men—the washing of pitchers and cups, and you do many other such things.”', pt: 'Vós deixais o mandamento de Deus, e vos apegais à tradição dos homens.' },
      { v: 9, en: 'He said to them, “Full well do you reject the commandment of God, that you may keep your tradition.', pt: 'Disse-lhes ainda: Bem sabeis rejeitar o mandamento de deus, para guardardes a vossa tradição.' },
      { v: 10, en: 'For Moses said, ‘Honor your father and your mother;’ and, ‘He who speaks evil of father or mother, let him be put to death.’', pt: 'Pois Moisés disse: Honra a teu pai e a tua mãe; e: Quem maldisser ao pai ou à mãe, certamente morrerá.' },
      { v: 11, en: 'But you say, ‘If a man tells his father or his mother, “Whatever profit you might have received from me is Corban, that is to say, given to God”;’', pt: 'Mas vós dizeis: Se um homem disser a seu pai ou a sua mãe: Aquilo que poderías aproveitar de mim é Corbã, isto é, oferta ao Senhor,' },
      { v: 12, en: 'then you no longer allow him to do anything for his father or his mother,', pt: 'não mais lhe permitis fazer coisa alguma por seu pai ou por sua mãe,' },
      { v: 13, en: 'making void the word of God by your tradition, which you have handed down. You do many things like this.”', pt: 'invalidando assim a palavra de Deus pela vossa tradição que vós transmitistes; também muitas outras coisas semelhantes fazeis.' },
      { v: 14, en: 'He called all the multitude to himself, and said to them, “Hear me, all of you, and understand.', pt: 'E chamando a si outra vez a multidão, disse-lhes: Ouvi-me vós todos, e entendei.' },
      { v: 15, en: 'There is nothing from outside of the man, that going into him can defile him; but the things which proceed out of the man are those that defile the man.', pt: 'Nada há fora do homem que, entrando nele, possa contaminá-lo; mas o que sai do homem, isso é que o contamina.' },
      { v: 16, en: 'If anyone has ears to hear, let him hear!”', pt: '[Se alguém tem ouvidos para ouvir, ouça.]' },
      { v: 17, en: 'When he had entered into a house away from the multitude, his disciples asked him about the parable.', pt: 'Depois, quando deixou a multidão e entrou em casa, os seus discípulos o interrogaram acerca da parábola.' },
      { v: 18, en: 'He said to them, “Are you also without understanding? Don’t you perceive that whatever goes into the man from outside can’t defile him,', pt: 'Respondeu-lhes ele: Assim também vós estais sem entender? Não compreendeis que tudo o que de fora entra no homem não o pode contaminar,' },
      { v: 19, en: 'because it doesn’t go into his heart, but into his stomach, then into the latrine, thus purifying all foods ?”', pt: 'porque não lhe entra no coração, mas no ventre, e é lançado fora? Assim declarou puros todos os alimentos.' },
      { v: 20, en: 'He said, “That which proceeds out of the man, that defiles the man.', pt: 'E prosseguiu: O que sai do homem , isso é que o contamina.' },
      { v: 21, en: 'For from within, out of the hearts of men, proceed evil thoughts, adulteries, sexual sins, murders, thefts,', pt: 'Pois é do interior, do coração dos homens, que procedem os maus pensamentos, as prostituições, os furtos, os homicídios, os adultérios,' },
      { v: 22, en: 'covetings, wickedness, deceit, lustful desires, an evil eye, blasphemy, pride, and foolishness.', pt: 'a cobiça, as maldades, o dolo, a libertinagem, a inveja, a blasfêmia, a soberba, a insensatez;' },
      { v: 23, en: 'All these evil things come from within, and defile the man.”', pt: 'todas estas más coisas procedem de dentro e contaminam o homem.' },
      { v: 24, en: 'From there he arose, and went away into the borders of Tyre and Sidon. He entered into a house, and didn’t want anyone to know it, but he couldn’t escape notice.', pt: 'Levantando-se dali, foi para as regiões de Tiro e Sidom. E entrando numa casa, não queria que ninguém o soubesse, mas não pode ocultar-se;' },
      { v: 25, en: 'For a woman, whose little daughter had an unclean spirit, having heard of him, came and fell down at his feet.', pt: 'porque logo, certa mulher, cuja filha estava possessa de um espírito imundo, ouvindo falar dele, veio e prostrou-se-lhe aos pés;' },
      { v: 26, en: 'Now the woman was a Greek, a Syrophoenician by race. She begged him that he would cast the demon out of her daughter.', pt: '(ora, a mulher era grega, de origem siro-fenícia) e rogava-lhe que expulsasse de sua filha o demônio.' },
      { v: 27, en: 'But Jesus said to her, “Let the children be filled first, for it is not appropriate to take the children’s bread and throw it to the dogs.”', pt: 'Respondeu-lhes Jesus: Deixa que primeiro se fartem os filhos; porque não é bom tomar o pão dos filhos e lança-lo aos cachorrinhos.' },
      { v: 28, en: 'But she answered him, “Yes, Lord. Yet even the dogs under the table eat the children’s crumbs.”', pt: 'Ela, porém, replicou, e disse-lhe: Sim, Senhor; mas também os cachorrinhos debaixo da mesa comem das migalhas dos filhos.' },
      { v: 29, en: 'He said to her, “For this saying, go your way. The demon has gone out of your daughter.”', pt: 'Então ele lhe disse: Por essa palavra, vai; o demônio já saiu de tua filha.' },
      { v: 30, en: 'She went away to her house, and found the child having been laid on the bed, with the demon gone out.', pt: 'E, voltando ela para casa, achou a menina deitada sobre a cama, e que o demônio já havia saído.' },
      { v: 31, en: 'Again he departed from the borders of Tyre and Sidon, and came to the sea of Galilee, through the middle of the region of Decapolis.', pt: 'Tendo Jesus partido das regiões de Tiro, foi por Sidom até o mar da Galiléia, passando pelas regiões de Decápolis.' },
      { v: 32, en: 'They brought to him one who was deaf and had an impediment in his speech. They begged him to lay his hand on him.', pt: 'E trouxeram-lhe um surdo, que falava dificilmente; e rogaram-lhe que pusesse a mão sobre ele.' },
      { v: 33, en: 'He took him aside from the multitude, privately, and put his fingers into his ears, and he spat, and touched his tongue.', pt: 'Jesus, pois, tirou-o de entre a multidão, à parte, meteu-lhe os dedos nos ouvidos e, cuspindo, tocou-lhe na língua;' },
      { v: 34, en: 'Looking up to heaven, he sighed, and said to him, “Ephphatha!” that is, “Be opened!”', pt: 'e erguendo os olhos ao céu, suspirou e disse-lhe: Efatá; isto é Abre-te.' },
      { v: 35, en: 'Immediately his ears were opened, and the impediment of his tongue was released, and he spoke clearly.', pt: 'E abriram-se-lhe os ouvidos, a prisão da língua se desfez, e falava perfeitamente.' },
      { v: 36, en: 'He commanded them that they should tell no one, but the more he commanded them, so much the more widely they proclaimed it.', pt: 'Então lhes ordenou Jesus que a ninguém o dissessem; mas, quando mais lho proibia, tanto mais o divulgavam.' },
      { v: 37, en: 'They were astonished beyond measure, saying, “He has done all things well. He makes even the deaf hear, and the mute speak!”', pt: 'E se maravilhavam sobremaneira, dizendo: Tudo tem feito bem; faz até os surdos ouvir e os mudos falar.' },
    ],
    8: [
      { v: 1, en: 'In those days, when there was a very great multitude, and they had nothing to eat, Jesus called his disciples to himself, and said to them,', pt: 'Naqueles dias, havendo de novo uma grande multidão, e não tendo o que comer, chamou Jesus os discípulos e disse-lhes:' },
      { v: 2, en: '“I have compassion on the multitude, because they have stayed with me now three days, and have nothing to eat.', pt: 'Tenho compaixão da multidão, porque já faz três dias que eles estão comigo, e não têm o que comer.' },
      { v: 3, en: 'If I send them away fasting to their home, they will faint on the way, for some of them have come a long way.”', pt: 'Se eu os mandar em jejum para suas casas, desfalecerão no caminho; e alguns deles vieram de longe.' },
      { v: 4, en: 'His disciples answered him, “From where could one satisfy these people with bread here in a deserted place?”', pt: 'E seus discípulos lhe responderam: Donde poderá alguém satisfazê-los de pão aqui no deserto?' },
      { v: 5, en: 'He asked them, “How many loaves do you have?” They said, “Seven.”', pt: 'Perguntou-lhes Jesus: Quantos pães tendes? Responderam: Sete.' },
      { v: 6, en: 'He commanded the multitude to sit down on the ground, and he took the seven loaves. Having given thanks, he broke them, and gave them to his disciples to serve, and they served the multitude.', pt: 'Logo mandou ao povo que se sentasse no chão; e tomando os sete pães e havendo dado graças, partiu-os e os entregava a seus discípulos para que os distribuíssem; e eles os distribuíram pela multidão.' },
      { v: 7, en: 'They had a few small fish. Having blessed them, he said to serve these also.', pt: 'Tinham também alguns peixinhos, os quais ele abençoou, e mandou que estes também fossem distribuídos.' },
      { v: 8, en: 'They ate, and were filled. They took up seven baskets of broken pieces that were left over.', pt: 'Comeram, pois, e se fartaram; e dos pedaços que sobejavam levantaram sete alcofas.' },
      { v: 9, en: 'Those who had eaten were about four thousand. Then he sent them away.', pt: 'Ora, eram cerca de quatro mil homens. E Jesus os despediu.' },
      { v: 10, en: 'Immediately he entered into the boat with his disciples, and came into the region of Dalmanutha.', pt: 'E, entrando logo no barco com seus discípulos, foi para as regiões de Dalmanuta.' },
      { v: 11, en: 'The Pharisees came out and began to question him, seeking from him a sign from heaven, and testing him.', pt: 'Saíram os fariseus e começaram a discutir com ele, pedindo-lhe um sinal do céu, para o experimentarem.' },
      { v: 12, en: 'He sighed deeply in his spirit, and said, “Why does this generation seek a sign? Most certainly I tell you, no sign will be given to this generation.”', pt: 'Ele, suspirando profundamente em seu espírito, disse: Por que pede esta geração um sinal? Em verdade vos digo que a esta geração não será dado sinal algum.' },
      { v: 13, en: 'He left them, and again entering into the boat, departed to the other side.', pt: 'E, deixando-os, tornou a embarcar e foi para o outro lado.' },
      { v: 14, en: 'They forgot to take bread; and they didn’t have more than one loaf in the boat with them.', pt: 'Ora, eles se esqueceram de levar pão, e no barco não tinham consigo senão um pão.' },
      { v: 15, en: 'He warned them, saying, “Take heed: beware of the yeast of the Pharisees and the yeast of Herod.”', pt: 'E Jesus ordenou-lhes, dizendo: Olhai, guardai-vos do fermento dos fariseus e do fermento de Herodes.' },
      { v: 16, en: 'They reasoned with one another, saying, “It’s because we have no bread.”', pt: 'Pelo que eles arrazoavam entre si porque não tinham pão.' },
      { v: 17, en: 'Jesus, perceiving it, said to them, “Why do you reason that it’s because you have no bread? Don’t you perceive yet, neither understand? Is your heart still hardened?', pt: 'E Jesus, percebendo isso, disse-lhes: Por que arrazoais por não terdes pão? não compreendeis ainda, nem entendeis? tendes o vosso coração endurecido?' },
      { v: 18, en: 'Having eyes, don’t you see? Having ears, don’t you hear? Don’t you remember?', pt: 'Tendo olhos, não vedes? e tendo ouvidos, não ouvis? e não vos lembrais?' },
      { v: 19, en: 'When I broke the five loaves among the five thousand, how many baskets full of broken pieces did you take up?” They told him, “Twelve.”', pt: 'Quando parti os cinco pães para os cinco mil, quantos cestos cheios de pedaços levantastes? Responderam-lhe: Doze.' },
      { v: 20, en: '“When the seven loaves fed the four thousand, how many baskets full of broken pieces did you take up?” They told him, “Seven.”', pt: 'E quando parti os sete para os quatro mil, quantas alcofas cheias de pedaços levantastes? Responderam-lhe: Sete.' },
      { v: 21, en: 'He asked them, “Don’t you understand yet?”', pt: 'E ele lhes disse: Não entendeis ainda?' },
      { v: 22, en: 'He came to Bethsaida. They brought a blind man to him, and begged him to touch him.', pt: 'Então chegaram a Betsaída. E trouxeram-lhe um cego, e rogaram-lhe que o tocasse.' },
      { v: 23, en: 'He took hold of the blind man by the hand, and brought him out of the village. When he had spat on his eyes, and laid his hands on him, he asked him if he saw anything.', pt: 'Jesus, pois, tomou o cego pela mão, e o levou para fora da aldeia; e cuspindo-lhe nos olhos, e impondo-lhe as mãos, perguntou-lhe: Vês alguma coisa?' },
      { v: 24, en: 'He looked up, and said, “I see men; for I see them like trees walking.”', pt: 'E, levantando ele os olhos, disse: Estou vendo os homens; porque como árvores os vejo andando.' },
      { v: 25, en: 'Then again he laid his hands on his eyes. He looked intently, and was restored, and saw everyone clearly.', pt: 'Então tornou a pôr-lhe as mãos sobre os olhos; e ele, olhando atentamente, ficou restabelecido, pois já via nitidamente todas as coisas.' },
      { v: 26, en: 'He sent him away to his house, saying, “Don’t enter into the village, nor tell anyone in the village.”', pt: 'Depois o mandou para casa, dizendo: Mas não entres na aldeia.' },
      { v: 27, en: 'Jesus went out, with his disciples, into the villages of Caesarea Philippi. On the way he asked his disciples, “Who do men say that I am?”', pt: 'E saiu Jesus com os seus discípulos para as aldeias de Cesaréia de Filipe, e no caminho interrogou os discípulos, dizendo: Quem dizem os homens que eu sou?' },
      { v: 28, en: 'They told him, “John the Baptizer, and others say Elijah, but others: one of the prophets.”', pt: 'Responderam-lhe eles: Uns dizem: João, o Batista; outros: Elias; e ainda outros: Algum dos profetas.' },
      { v: 29, en: 'He said to them, “But who do you say that I am?” Peter answered, “You are the Christ.”', pt: 'Então lhes perguntou: Mas vós, quem dizeis que eu sou? Respondendo, Pedro lhe disse: Tu és o Cristo.' },
      { v: 30, en: 'He commanded them that they should tell no one about him.', pt: 'E ordenou-lhes Jesus que a ninguém dissessem aquilo a respeito dele.' },
      { v: 31, en: 'He began to teach them that the Son of Man must suffer many things, and be rejected by the elders, the chief priests, and the scribes, and be killed, and after three days rise again.', pt: 'Começou então a ensinar-lhes que era necessário que o Filho do homem padecesse muitas coisas, que fosse rejeitado pelos anciãos e principais sacerdotes e pelos escribas, que fosse morto, e que depois de três dias ressurgisse.' },
      { v: 32, en: 'He spoke to them openly. Peter took him, and began to rebuke him.', pt: 'E isso dizia abertamente. Ao que Pedro, tomando-o à parte, começou a repreendê-lo.' },
      { v: 33, en: 'But he, turning around, and seeing his disciples, rebuked Peter, and said, “Get behind me, Satan! For you have in mind not the things of God, but the things of men.”', pt: 'Mas ele, virando-se olhando para seus discípulos, repreendeu a Pedro, dizendo: Para trás de mim, Satanás; porque não cuidas das coisas que são de Deus, mas sim das que são dos homens.' },
      { v: 34, en: 'He called the multitude to himself with his disciples, and said to them, “Whoever wants to come after me, let him deny himself, and take up his cross, and follow me.', pt: 'E chamando a si a multidão com os discípulos, disse-lhes: Se alguém quer vir após mim, negue-se a si mesmo, tome a sua cruz, e siga-me.' },
      { v: 35, en: 'For whoever wants to save his life will lose it; and whoever will lose his life for my sake and the sake of the Good News will save it.', pt: 'Pois quem quiser salvar a sua vida, perdê-la-á; mas quem perder a sua vida por amor de mim e do evangelho, salvá-la-á.' },
      { v: 36, en: 'For what does it profit a man, to gain the whole world, and forfeit his life?', pt: 'Pois que aproveita ao homem ganhar o mundo inteiro e perder a sua vida?' },
      { v: 37, en: 'For what will a man give in exchange for his life?', pt: 'Ou que diria o homem em troca da sua vida?' },
      { v: 38, en: 'For whoever will be ashamed of me and of my words in this adulterous and sinful generation, the Son of Man also will be ashamed of him, when he comes in his Father’s glory, with the holy angels.”', pt: 'Porquanto, qualquer que, entre esta geração adúltera e pecadora, se envergonhar de mim e das minhas palavras, também dele se envergonhará o Filho do homem quando vier na glória de seu Pai com os santos anjos.' },
    ],
    9: [
      { v: 1, en: 'He said to them, “Most certainly I tell you, there are some standing here who will in no way taste death until they see God’s Kingdom come with power.”', pt: 'Disse-lhes mais: Em verdade vos digo que, dos que aqui estão, alguns há que de modo nenhum provarão a morte até que vejam o reino de Deus já chegando com poder.' },
      { v: 2, en: 'After six days Jesus took with him Peter, James, and John, and brought them up onto a high mountain privately by themselves, and he was changed into another form in front of them.', pt: 'Seis dias depois tomou Jesus consigo a Pedro, a Tiago, e a João, e os levou à parte sós, a um alto monte; e foi transfigurado diante deles;' },
      { v: 3, en: 'His clothing became glistening, exceedingly white, like snow, such as no launderer on earth can whiten them.', pt: 'as suas vestes tornaram-se resplandecentes, extremamente brancas, tais como nenhum lavandeiro sobre a terra as poderia branquear.' },
      { v: 4, en: 'Elijah and Moses appeared to them, and they were talking with Jesus.', pt: 'E apareceu-lhes Elias com Moisés, e falavam com Jesus.' },
      { v: 5, en: 'Peter answered Jesus, “Rabbi, it is good for us to be here. Let’s make three tents: one for you, one for Moses, and one for Elijah.”', pt: 'Pedro, tomando a palavra, disse a Jesus: Mestre, bom é estarmos aqui; faça-mos, pois, três cabanas, uma para ti, outra para Moisés, e outra para Elias.' },
      { v: 6, en: 'For he didn’t know what to say, for they were very afraid.', pt: 'Pois não sabia o que havia de dizer, porque ficaram atemorizados.' },
      { v: 7, en: 'A cloud came, overshadowing them, and a voice came out of the cloud, “This is my beloved Son. Listen to him.”', pt: 'Nisto veio uma nuvem que os cobriu, e dela saiu uma voz que dizia: Este é o meu Filho amado; a ele ouvi.' },
      { v: 8, en: 'Suddenly looking around, they saw no one with them any more, except Jesus only.', pt: 'De repente, tendo olhado em redor, não viram mais a ninguém consigo, senão só a Jesus.' },
      { v: 9, en: 'As they were coming down from the mountain, he commanded them that they should tell no one what things they had seen, until after the Son of Man had risen from the dead.', pt: 'Enquanto desciam do monte, ordenou-lhes que a ninguém contassem o que tinham visto, até que o Filho do homem ressurgisse dentre os mortos.' },
      { v: 10, en: 'They kept this saying to themselves, questioning what the “rising from the dead” meant.', pt: 'E eles guardaram o caso em segredo, indagando entre si o que seria o ressurgir dentre os mortos.' },
      { v: 11, en: 'They asked him, saying, “Why do the scribes say that Elijah must come first?”', pt: 'Então lhe perguntaram: Por que dizem os escribas que é necessário que Elias venha primeiro?' },
      { v: 12, en: 'He said to them, “Elijah indeed comes first, and restores all things. How is it written about the Son of Man, that he should suffer many things and be despised?', pt: 'Respondeu-lhes Jesus: Na verdade Elias havia de vir primeiro, a restaurar todas as coisas; e como é que está escrito acerca do Filho do homem que ele deva padecer muito a ser aviltado?' },
      { v: 13, en: 'But I tell you that Elijah has come, and they have also done to him whatever they wanted to, even as it is written about him.”', pt: 'Digo-vos, porém, que Elias já veio, e fizeram-lhe tudo quanto quiseram, como dele está escrito.' },
      { v: 14, en: 'Coming to the disciples, he saw a great multitude around them, and scribes questioning them.', pt: 'Quando chegaram aonde estavam os discípulos, viram ao redor deles uma grande multidão, e alguns escribas a discutirem com eles.' },
      { v: 15, en: 'Immediately all the multitude, when they saw him, were greatly amazed, and running to him, greeted him.', pt: 'E logo toda a multidão, vendo a Jesus, ficou grandemente surpreendida; e correndo todos para ele, o saudavam.' },
      { v: 16, en: 'He asked the scribes, “What are you asking them?”', pt: 'Perguntou ele aos escribas: Que é que discutis com eles?' },
      { v: 17, en: 'One of the multitude answered, “Teacher, I brought to you my son, who has a mute spirit;', pt: 'Respondeu-lhe um dentre a multidão: Mestre, eu te trouxe meu filho, que tem um espírito mudo;' },
      { v: 18, en: 'and wherever it seizes him, it throws him down, and he foams at the mouth, and grinds his teeth, and wastes away. I asked your disciples to cast it out, and they weren’t able.”', pt: 'e este, onde quer que o apanha, convulsiona-o, de modo que ele espuma, range os dentes, e vai definhando; e eu pedi aos teus discípulos que o expulsassem, e não puderam.' },
      { v: 19, en: 'He answered him, “Unbelieving generation, how long shall I be with you? How long shall I bear with you? Bring him to me.”', pt: 'Ao que Jesus lhes respondeu: Ó geração incrédula! até quando estarei convosco? até quando vos hei de suportar? Trazei-mo.' },
      { v: 20, en: 'They brought him to him, and when he saw him, immediately the spirit convulsed him, and he fell on the ground, wallowing and foaming at the mouth.', pt: 'Então lho trouxeram; e quando ele viu a Jesus, o espírito imediatamente o convulsionou; e o endemoninhado, caindo por terra, revolvia-se espumando.' },
      { v: 21, en: 'He asked his father, “How long has it been since this has come to him?” He said, “From childhood.', pt: 'E perguntou Jesus ao pai dele: Há quanto tempo sucede-lhe isto? Respondeu ele: Desde a infância;' },
      { v: 22, en: 'Often it has cast him both into the fire and into the water, to destroy him. But if you can do anything, have compassion on us, and help us.”', pt: 'e muitas vezes o tem lançado no fogo, e na água, para o destruir; mas se podes fazer alguma coisa, tem compaixão de nós e ajuda-nos.' },
      { v: 23, en: 'Jesus said to him, “If you can believe, all things are possible to him who believes.”', pt: 'Ao que lhe disse Jesus: Se podes! - tudo é possível ao que crê.' },
      { v: 24, en: 'Immediately the father of the child cried out with tears, “I believe. Help my unbelief!”', pt: 'Imediatamente o pai do menino, clamando, [com lágrimas] disse: Creio! Ajuda a minha incredulidade.' },
      { v: 25, en: 'When Jesus saw that a multitude came running together, he rebuked the unclean spirit, saying to him, “You mute and deaf spirit, I command you, come out of him, and never enter him again!”', pt: 'E Jesus, vendo que a multidão, correndo, se aglomerava, repreendeu o espírito imundo, dizendo: Espírito mudo e surdo, eu te ordeno: Sai dele, e nunca mais entres nele.' },
      { v: 26, en: 'After crying out and convulsing him greatly, it came out of him. The boy became like one dead; so much that most of them said, “He is dead.”', pt: 'E ele, gritando, e agitando-o muito, saiu; e ficou o menino como morto, de modo que a maior parte dizia: Morreu.' },
      { v: 27, en: 'But Jesus took him by the hand, and raised him up; and he arose.', pt: 'Mas Jesus, tomando-o pela mão, o ergueu; e ele ficou em pé.' },
      { v: 28, en: 'When he had come into the house, his disciples asked him privately, “Why couldn’t we cast it out?”', pt: 'E quando entrou em casa, seus discípulos lhe perguntaram à parte: Por que não pudemos nós expulsá-lo?' },
      { v: 29, en: 'He said to them, “This kind can come out by nothing, except by prayer and fasting.”', pt: 'Respondeu-lhes: Esta casta não sai de modo algum, salvo à força de oração [e jejum.]' },
      { v: 30, en: 'They went out from there, and passed through Galilee. He didn’t want anyone to know it.', pt: 'Depois, tendo partido dali, passavam pela Galiléia, e ele não queria que ninguém o soubesse;' },
      { v: 31, en: 'For he was teaching his disciples, and said to them, “The Son of Man is being handed over to the hands of men, and they will kill him; and when he is killed, on the third day he will rise again.”', pt: 'porque ensinava a seus discípulos, e lhes dizia: O Filho do homem será entregue nas mãos dos homens, que o matarão; e morto ele, depois de três dias ressurgirá.' },
      { v: 32, en: 'But they didn’t understand the saying, and were afraid to ask him.', pt: 'Mas eles não entendiam esta palavra, e temiam interrogá-lo.' },
      { v: 33, en: 'He came to Capernaum, and when he was in the house he asked them, “What were you arguing among yourselves on the way?”', pt: 'Chegaram a Cafarnaum. E estando ele em casa, perguntou-lhes: Que estáveis discutindo pelo caminho?' },
      { v: 34, en: 'But they were silent, for they had disputed one with another on the way about who was the greatest.', pt: 'Mas eles se calaram, porque pelo caminho haviam discutido entre si qual deles era o maior.' },
      { v: 35, en: 'He sat down, and called the twelve; and he said to them, “If any man wants to be first, he shall be last of all, and servant of all.”', pt: 'E ele, sentando-se, chamou os doze e lhes disse: se alguém quiser ser o primeiro, será o derradeiro de todos e o servo de todos.' },
      { v: 36, en: 'He took a little child, and set him in the middle of them. Taking him in his arms, he said to them,', pt: 'Então tomou uma criança, pô-la no meio deles e, abraçando-a, disse-lhes:' },
      { v: 37, en: '“Whoever receives one such little child in my name, receives me, and whoever receives me, doesn’t receive me, but him who sent me.”', pt: 'Qualquer que em meu nome receber uma destas crianças, a mim me recebe; e qualquer que me recebe a mim, recebe não a mim mas àquele que me enviou.' },
      { v: 38, en: 'John said to him, “Teacher, we saw someone who doesn’t follow us casting out demons in your name; and we forbade him, because he doesn’t follow us.”', pt: 'Disse-lhe João: Mestre, vimos um homem que em teu nome expulsava demônios, e nós lho proibimos, porque não nos seguia.' },
      { v: 39, en: 'But Jesus said, “Don’t forbid him, for there is no one who will do a mighty work in my name, and be able quickly to speak evil of me.', pt: 'Jesus, porém, respondeu: Não lho proibais; porque ninguém há que faça milagre em meu nome e possa logo depois falar mal de mim;' },
      { v: 40, en: 'For whoever is not against us is on our side.', pt: 'pois quem não é contra nós, é por nós.' },
      { v: 41, en: 'For whoever will give you a cup of water to drink in my name, because you are Christ’s, most certainly I tell you, he will in no way lose his reward.', pt: 'Porquanto qualquer que vos der a beber um copo de água em meu nome, porque sois de Cristo, em verdade vos digo que de modo algum perderá a sua recompensa.' },
      { v: 42, en: 'Whoever will cause one of these little ones who believe in me to stumble, it would be better for him if he were thrown into the sea with a millstone hung around his neck.', pt: 'Mas qualquer que fizer tropeçar um destes pequeninos que crêem em mim, melhor lhe fora que se lhe pendurasse ao pescoço uma pedra de moinho, e que fosse lançado no mar.' },
      { v: 43, en: 'If your hand causes you to stumble, cut it off. It is better for you to enter into life maimed, rather than having your two hands to go into Gehenna, into the unquenchable fire,', pt: 'E se a tua mão te fizer tropeçar, corta-a; melhor é entrares na vida aleijado, do que, tendo duas mãos, ires para o inferno, para o fogo que nunca se apaga.' },
      { v: 44, en: '‘where their worm doesn’t die, and the fire is not quenched.’', pt: '[onde o seu verme não morre, e o fogo não se apaga.]' },
      { v: 45, en: 'If your foot causes you to stumble, cut it off. It is better for you to enter into life lame, rather than having your two feet to be cast into Gehenna, into the fire that will never be quenched—', pt: 'Ou, se o teu pé te fizer tropeçar, corta-o; melhor é entrares coxo na vida, do que, tendo dois pés, seres lançado no inferno.' },
      { v: 46, en: '‘where their worm doesn’t die, and the fire is not quenched.’', pt: '[onde o seu verme não morre, e o fogo não se apaga.]' },
      { v: 47, en: 'If your eye causes you to stumble, cast it out. It is better for you to enter into God’s Kingdom with one eye, rather than having two eyes to be cast into the Gehenna of fire,', pt: 'Ou, se o teu olho te fizer tropeçar, lança-o fora; melhor é entrares no reino de Deus com um só olho, do que, tendo dois olhos, seres lançado no inferno.' },
      { v: 48, en: '‘where their worm doesn’t die, and the fire is not quenched.’', pt: 'onde o seu verme não morre, e o fogo não se apaga.' },
      { v: 49, en: 'For everyone will be salted with fire, and every sacrifice will be seasoned with salt.', pt: 'Porque cada um será salgado com fogo.' },
      { v: 50, en: 'Salt is good, but if the salt has lost its saltiness, with what will you season it? Have salt in yourselves, and be at peace with one another.”', pt: 'Bom é o sal; mas, se o sal se tornar insípido, com que o haveis de temperar? Tende sal em vós mesmos, e guardai a paz uns com os outros.' },
    ],
    10: [
      { v: 1, en: 'He arose from there and came into the borders of Judea and beyond the Jordan. Multitudes came together to him again. As he usually did, he was again teaching them.', pt: 'Levantando-se Jesus, partiu dali para os termos da Judéia, e para além do Jordão; e do novo as multidões se reuniram em torno dele; e tornou a ensiná-las, como tinha por costume.' },
      { v: 2, en: 'Pharisees came to him testing him, and asked him, “Is it lawful for a man to divorce his wife?”', pt: 'Então se aproximaram dele alguns fariseus e, para o experimentarem, lhe perguntaram: É lícito ao homem repudiar sua mulher?' },
      { v: 3, en: 'He answered, “What did Moses command you?”', pt: 'Ele, porém, respondeu-lhes: Que vos ordenou Moisés?' },
      { v: 4, en: 'They said, “Moses allowed a certificate of divorce to be written, and to divorce her.”', pt: 'Replicaram eles: Moisés permitiu escrever carta de divórcio, e repudiar a mulher.' },
      { v: 5, en: 'But Jesus said to them, “For your hardness of heart, he wrote you this commandment.', pt: 'Disse-lhes Jesus: Pela dureza dos vossos corações ele vos deixou escrito esse mandamento.' },
      { v: 6, en: 'But from the beginning of the creation, God made them male and female.', pt: 'Mas desde o princípio da criação, Deus os fez homem e mulher.' },
      { v: 7, en: 'For this cause a man will leave his father and mother, and will join to his wife,', pt: 'Por isso deixará o homem a seu pai e a sua mãe, [e unir-se-á à sua mulher,]' },
      { v: 8, en: 'and the two will become one flesh, so that they are no longer two, but one flesh.', pt: 'e serão os dois uma só carne; assim já não são mais dois, mas uma só carne.' },
      { v: 9, en: 'What therefore God has joined together, let no man separate.”', pt: 'Porquanto o que Deus ajuntou, não o separe o homem.' },
      { v: 10, en: 'In the house, his disciples asked him again about the same matter.', pt: 'Em casa os discípulos interrogaram-no de novo sobre isso.' },
      { v: 11, en: 'He said to them, “Whoever divorces his wife, and marries another, commits adultery against her.', pt: 'Ao que lhes respondeu: Qualquer que repudiar sua mulher e casar com outra comete adultério contra ela;' },
      { v: 12, en: 'If a woman herself divorces her husband, and marries another, she commits adultery.”', pt: 'e se ela repudiar seu marido e casar com outro, comete adultério.' },
      { v: 13, en: 'They were bringing to him little children, that he should touch them, but the disciples rebuked those who were bringing them.', pt: 'Então lhe traziam algumas crianças para que as tocasse; mas os discípulos o repreenderam.' },
      { v: 14, en: 'But when Jesus saw it, he was moved with indignation, and said to them, “Allow the little children to come to me! Don’t forbid them, for God’s Kingdom belongs to such as these.', pt: 'Jesus, porém, vendo isto, indignou-se e disse-lhes: Deixai vir a mim as crianças, e não as impeçais, porque de tais é o reino de Deus.' },
      { v: 15, en: 'Most certainly I tell you, whoever will not receive God’s Kingdom like a little child, he will in no way enter into it.”', pt: 'Em verdade vos digo que qualquer que não receber o reino de Deus como criança, de maneira nenhuma entrará nele.' },
      { v: 16, en: 'He took them in his arms, and blessed them, laying his hands on them.', pt: 'E, tomando-as nos seus braços, as abençoou, pondo as mãos sobre elas.' },
      { v: 17, en: 'As he was going out into the way, one ran to him, knelt before him, and asked him, “Good Teacher, what shall I do that I may inherit eternal life?”', pt: 'Ora, ao sair para se pôr a caminho, correu para ele um homem, o qual se ajoelhou diante dele e lhe perguntou: Bom Mestre, que hei de fazer para herdar a vida eterna?' },
      { v: 18, en: 'Jesus said to him, “Why do you call me good? No one is good except one—God.', pt: 'Respondeu-lhe Jesus: Por que me chamas bom? ninguém é bom, senão um que é Deus.' },
      { v: 19, en: 'You know the commandments: ‘Do not murder,’ ‘Do not commit adultery,’ ‘Do not steal,’ ‘Do not give false testimony,’ ‘Do not defraud,’ ‘Honor your father and mother.’”', pt: 'Sabes os mandamentos: Não matarás; não adulterarás; não furtarás; não dirás falso testemunho; a ninguém defraudarás; honra a teu pai e a tua mãe.' },
      { v: 20, en: 'He said to him, “Teacher, I have observed all these things from my youth.”', pt: 'Ele, porém, lhe replicou: Mestre, tudo isso tenho guardado desde a minha juventude.' },
      { v: 21, en: 'Jesus looking at him loved him, and said to him, “One thing you lack. Go, sell whatever you have, and give to the poor, and you will have treasure in heaven; and come, follow me, taking up the cross.”', pt: 'E Jesus, olhando para ele, o amou e lhe disse: Uma coisa te falta; vai vende tudo quanto tens e dá-o aos pobres, e terás um tesouro no céu; e vem, segue-me.' },
      { v: 22, en: 'But his face fell at that saying, and he went away sorrowful, for he was one who had great possessions.', pt: 'Mas ele, pesaroso desta palavra, retirou-se triste, porque possuía muitos bens.' },
      { v: 23, en: 'Jesus looked around, and said to his disciples, “How difficult it is for those who have riches to enter into God’s Kingdom!”', pt: 'Então Jesus, olhando em redor, disse aos seus discípulos: Quão dificilmente entrarão no reino de Deus os que têm riquezas!' },
      { v: 24, en: 'The disciples were amazed at his words. But Jesus answered again, “Children, how hard is it for those who trust in riches to enter into God’s Kingdom!', pt: 'E os discípulos se maravilharam destas suas palavras; mas Jesus, tornando a falar, disse-lhes: Filhos, quão difícil é [para os que confiam nas riquezas] entrar no reino de Deus!' },
      { v: 25, en: 'It is easier for a camel to go through a needle’s eye than for a rich man to enter into God’s Kingdom.”', pt: 'É mais fácil um camelo passar pelo fundo de uma agulha, do que entrar um rico no reino de Deus.' },
      { v: 26, en: 'They were exceedingly astonished, saying to him, “Then who can be saved?”', pt: 'Com isso eles ficaram sobremaneira maravilhados, dizendo entre si: Quem pode, então, ser salvo?' },
      { v: 27, en: 'Jesus, looking at them, said, “With men it is impossible, but not with God, for all things are possible with God.”', pt: 'Jesus, fixando os olhos neles, respondeu: Para os homens é impossível, mas não para Deus; porque para Deus tudo é possível.' },
      { v: 28, en: 'Peter began to tell him, “Behold, we have left all, and have followed you.”', pt: 'Pedro começou a dizer-lhe: Eis que nós deixamos tudo e te seguimos.' },
      { v: 29, en: 'Jesus said, “Most certainly I tell you, there is no one who has left house, or brothers, or sisters, or father, or mother, or wife, or children, or land, for my sake, and for the sake of the Good News,', pt: 'Respondeu Jesus: Em verdade vos digo que ninguém há, que tenha deixado casa, ou irmãos, ou irmãs, ou mãe, ou pai, ou filhos, ou campos, por amor de mim e do evangelho,' },
      { v: 30, en: 'but he will receive one hundred times more now in this time, houses, brothers, sisters, mothers, children, and land, with persecutions; and in the age to come eternal life.', pt: 'que não receba cem vezes tanto, já neste tempo, em casas, e irmãos, e irmãs, e mães, e filhos, e campos, com perseguições; e no mundo vindouro a vida eterna.' },
      { v: 31, en: 'But many who are first will be last; and the last first.”', pt: 'Mas muitos que são primeiros serão últimos; e muitos que são últimos serão primeiros.' },
      { v: 32, en: 'They were on the way, going up to Jerusalem; and Jesus was going in front of them, and they were amazed; and those who followed were afraid. He again took the twelve, and began to tell them the things that were going to happen to him.', pt: 'Ora, estavam a caminho, subindo para Jerusalém; e Jesus ia adiante deles, e eles se maravilhavam e o seguiam atemorizados. De novo tomou consigo os doze e começou a contar-lhes as coisas que lhe haviam de sobrevir,' },
      { v: 33, en: '“Behold, we are going up to Jerusalem. The Son of Man will be delivered to the chief priests and the scribes. They will condemn him to death, and will deliver him to the Gentiles.', pt: 'dizendo: Eis que subimos a Jerusalém, e o Filho do homem será entregue aos principais sacerdotes e aos escribas; e eles o condenarão à morte, e o entregarão aos gentios;' },
      { v: 34, en: 'They will mock him, spit on him, scourge him, and kill him. On the third day he will rise again.”', pt: 'e hão de escarnecê-lo e cuspir nele, e açoitá-lo, e matá-lo; e depois de três dias ressurgirá.' },
      { v: 35, en: 'James and John, the sons of Zebedee, came near to him, saying, “Teacher, we want you to do for us whatever we will ask.”', pt: 'Nisso aproximaram-se dele Tiago e João, filhos de Zebedeu, dizendo-lhe: Mestre, queremos que nos faças o que te pedirmos.' },
      { v: 36, en: 'He said to them, “What do you want me to do for you?”', pt: 'Ele, pois, lhes perguntou: Que quereis que eu vos faça?' },
      { v: 37, en: 'They said to him, “Grant to us that we may sit, one at your right hand, and one at your left hand, in your glory.”', pt: 'Responderam-lhe: Concede-nos que na tua glória nos sentemos, um à tua direita, e outro à tua esquerda.' },
      { v: 38, en: 'But Jesus said to them, “You don’t know what you are asking. Are you able to drink the cup that I drink, and to be baptized with the baptism that I am baptized with?”', pt: 'Mas Jesus lhes disse: Não sabeis o que pedis; podeis beber o cálice que eu bebo, e ser batizados no batismo em que eu sou batizado?' },
      { v: 39, en: 'They said to him, “We are able.” Jesus said to them, “You shall indeed drink the cup that I drink, and you shall be baptized with the baptism that I am baptized with;', pt: 'E lhe responderam: Podemos. Mas Jesus lhes disse: O cálice que eu bebo, haveis de bebê-lo, e no batismo em que eu sou batizado, haveis de ser batizados;' },
      { v: 40, en: 'but to sit at my right hand and at my left hand is not mine to give, but for whom it has been prepared.”', pt: 'mas o sentar-se à minha direita, ou à minha esquerda, não me pertence concedê-lo; mas isso é para aqueles a quem está reservado.' },
      { v: 41, en: 'When the ten heard it, they began to be indignant towards James and John.', pt: 'E ouvindo isso os dez, começaram a indignar-se contra Tiago e João.' },
      { v: 42, en: 'Jesus summoned them, and said to them, “You know that they who are recognized as rulers over the nations lord it over them, and their great ones exercise authority over them.', pt: 'Então Jesus chamou-os para junto de si e lhes disse: Sabeis que os que são reconhecidos como governadores dos gentios, deles se assenhoreiam, e que sobre eles os seus grandes exercem autoridade.' },
      { v: 43, en: 'But it shall not be so among you, but whoever wants to become great among you shall be your servant.', pt: 'Mas entre vós não será assim; antes, qualquer que entre vós quiser tornar-se grande, será esse o que vos sirva;' },
      { v: 44, en: 'Whoever of you wants to become first among you, shall be bondservant of all.', pt: 'e qualquer que entre vós quiser ser o primeiro, será servo de todos.' },
      { v: 45, en: 'For the Son of Man also came not to be served, but to serve, and to give his life as a ransom for many.”', pt: 'Pois também o Filho do homem não veio para ser servido, mas para servir, e para dar a sua vida em resgate de muitos.' },
      { v: 46, en: 'They came to Jericho. As he went out from Jericho, with his disciples and a great multitude, the son of Timaeus, Bartimaeus, a blind beggar, was sitting by the road.', pt: 'Depois chegaram a Jericó. E, ao sair ele de Jericó com seus discípulos e uma grande multidão, estava sentado junto do caminho um mendigo cego, Bartimeu filho de Timeu.' },
      { v: 47, en: 'When he heard that it was Jesus the Nazarene, he began to cry out, and say, “Jesus, you son of David, have mercy on me!”', pt: 'Este, quando ouviu que era Jesus, o nazareno, começou a clamar, dizendo: Jesus, Filho de Davi, tem compaixão de mim!' },
      { v: 48, en: 'Many rebuked him, that he should be quiet, but he cried out much more, “You son of David, have mercy on me!”', pt: 'E muitos o repreendiam, para que se calasse; mas ele clamava ainda mais: Filho de Davi, tem compaixão de mim.' },
      { v: 49, en: 'Jesus stood still, and said, “Call him.” They called the blind man, saying to him, “Cheer up! Get up. He is calling you!”', pt: 'Parou, pois, Jesus e disse: Chamai-o. E chamaram o cego, dizendo-lhe: Tem bom ânimo; levanta-te, ele te chama.' },
      { v: 50, en: 'He, casting away his cloak, sprang up, and came to Jesus.', pt: 'Nisto, lançando de si a sua capa, de um salto se levantou e foi ter com Jesus.' },
      { v: 51, en: 'Jesus asked him, “What do you want me to do for you?” The blind man said to him, “Rabboni, that I may see again.”', pt: 'Perguntou-lhe o cego: Que queres que te faça? Respondeu-lhe o cego: Mestre, que eu veja.' },
      { v: 52, en: 'Jesus said to him, “Go your way. Your faith has made you well.” Immediately he received his sight, and followed Jesus on the way.', pt: 'Disse-lhe Jesus: Vai, a tua fé te salvou. E imediatamente recuperou a vista, e foi seguindo pelo caminho.' },
    ],
    11: [
      { v: 1, en: 'When they came near to Jerusalem, to Bethsphage and Bethany, at the Mount of Olives, he sent two of his disciples,', pt: 'Ora, quando se aproximavam de Jerusalém, de Betfagé e de Betânia, junto do Monte das Oliveiras, enviou Jesus dois dos seus discípulos' },
      { v: 2, en: 'and said to them, “Go your way into the village that is opposite you. Immediately as you enter into it, you will find a young donkey tied, on which no one has sat. Untie him, and bring him.', pt: 'e disse-lhes: Ide à aldeia que está defronte de vós; e logo que nela entrardes, encontrareis preso um jumentinho, em que ainda ninguém montou; desprendei-o e trazei-o.' },
      { v: 3, en: 'If anyone asks you, ‘Why are you doing this?’ say, ‘The Lord needs him;’ and immediately he will send him back here.”', pt: 'E se alguém vos perguntar: Por que fazeis isso? respondei: O Senhor precisa dele, e logo tornará a enviá-lo para aqui.' },
      { v: 4, en: 'They went away, and found a young donkey tied at the door outside in the open street, and they untied him.', pt: 'Foram, pois, e acharam o jumentinho preso ao portão do lado de fora na rua, e o desprenderam.' },
      { v: 5, en: 'Some of those who stood there asked them, “What are you doing, untying the young donkey?”', pt: 'E alguns dos que ali estavam lhes perguntaram: Que fazeis, desprendendo o jumentinho?' },
      { v: 6, en: 'They said to them just as Jesus had said, and they let them go.', pt: 'Responderam como Jesus lhes tinha mandado; e lho deixaram levar.' },
      { v: 7, en: 'They brought the young donkey to Jesus, and threw their garments on it, and Jesus sat on it.', pt: 'Então trouxeram a Jesus o jumentinho e lançaram sobre ele os seus mantos; e Jesus montou nele.' },
      { v: 8, en: 'Many spread their garments on the way, and others were cutting down branches from the trees, and spreading them on the road.', pt: 'Muitos também estenderam pelo caminho os seus mantos, e outros, ramagens que tinham cortado nos campos.' },
      { v: 9, en: 'Those who went in front, and those who followed, cried out, “Hosanna! Blessed is he who comes in the name of the Lord!', pt: 'E tanto os que o precediam como os que o seguiam, clamavam: Hosana! bendito o que vem em nome do Senhor!' },
      { v: 10, en: 'Blessed is the kingdom of our father David that is coming in the name of the Lord! Hosanna in the highest!”', pt: 'Bendito o reino que vem, o reino de nosso pai Davi! Hosana nas alturas!' },
      { v: 11, en: 'Jesus entered into the temple in Jerusalem. When he had looked around at everything, it being now evening, he went out to Bethany with the twelve.', pt: 'Tendo Jesus entrado em Jerusalém, foi ao templo; e tendo observado tudo em redor, como já fosse tarde, saiu para Betânia com os doze.' },
      { v: 12, en: 'The next day, when they had come out from Bethany, he was hungry.', pt: 'No dia seguinte, depois de saírem de Betânia teve fome,' },
      { v: 13, en: 'Seeing a fig tree afar off having leaves, he came to see if perhaps he might find anything on it. When he came to it, he found nothing but leaves, for it was not the season for figs.', pt: 'e avistando de longe uma figueira que tinha folhas, foi ver se, porventura, acharia nela alguma coisa; e chegando a ela, nada achou senão folhas, porque não era tempo de figos.' },
      { v: 14, en: 'Jesus told it, “May no one ever eat fruit from you again!” and his disciples heard it.', pt: 'E Jesus, falando, disse à figueira: Nunca mais coma alguém fruto de ti. E seus discípulos ouviram isso.' },
      { v: 15, en: 'They came to Jerusalem, and Jesus entered into the temple, and began to throw out those who sold and those who bought in the temple, and overthrew the money changers’ tables, and the seats of those who sold the doves.', pt: 'Chegaram, pois, a Jerusalém. E entrando ele no templo, começou a expulsar os que ali vendiam e compravam; e derribou as mesas dos cambistas, e as cadeiras dos que vendiam pombas;' },
      { v: 16, en: 'He would not allow anyone to carry a container through the temple.', pt: 'e não consentia que ninguém atravessasse o templo levando qualquer utensílio;' },
      { v: 17, en: 'He taught, saying to them, “Isn’t it written, ‘My house will be called a house of prayer for all the nations?’ But you have made it a den of robbers!”', pt: 'e ensinava, dizendo-lhes: Não está escrito: A minha casa será chamada casa de oração para todas as nações? Vós, porém, a tendes feito covil de salteadores.' },
      { v: 18, en: 'The chief priests and the scribes heard it, and sought how they might destroy him. For they feared him, because all the multitude was astonished at his teaching.', pt: 'Ora, os principais sacerdotes e os escribas ouviram isto, e procuravam um modo de o matar; pois o temiam, porque toda a multidão se maravilhava da sua doutrina.' },
      { v: 19, en: 'When evening came, he went out of the city.', pt: 'Ao cair da tarde, saíam da cidade.' },
      { v: 20, en: 'As they passed by in the morning, they saw the fig tree withered away from the roots.', pt: 'Quando passavam na manhã seguinte, viram que a figueira tinha secado desde as raízes.' },
      { v: 21, en: 'Peter, remembering, said to him, “Rabbi, look! The fig tree which you cursed has withered away.”', pt: 'Então Pedro, lembrando-se, disse-lhe: Olha, Mestre, secou-se a figueira que amaldiçoaste.' },
      { v: 22, en: 'Jesus answered them, “Have faith in God.', pt: 'Respondeu-lhes Jesus: Tende fé em Deus.' },
      { v: 23, en: 'For most certainly I tell you, whoever may tell this mountain, ‘Be taken up and cast into the sea,’ and doesn’t doubt in his heart, but believes that what he says is happening; he shall have whatever he says.', pt: 'Em verdade vos digo que qualquer que disser a este monte: Ergue-te e lança-te no mar; e não duvidar em seu coração, mas crer que se fará aquilo que diz, assim lhe será feito.' },
      { v: 24, en: 'Therefore I tell you, all things whatever you pray and ask for, believe that you have received them, and you shall have them.', pt: 'Por isso vos digo que tudo o que pedirdes em oração, crede que o recebereis, e tê-lo-eis.' },
      { v: 25, en: 'Whenever you stand praying, forgive, if you have anything against anyone; so that your Father, who is in heaven, may also forgive you your transgressions.', pt: 'Quando estiverdes orando, perdoai, se tendes alguma coisa contra alguém, para que também vosso Pai que está no céu, vos perdoe as vossas ofensas.' },
      { v: 26, en: 'But if you do not forgive, neither will your Father in heaven forgive your transgressions.”', pt: '[Mas, se vós não perdoardes, também vosso Pai, que está no céu, não vos perdoará as vossas ofensas.]' },
      { v: 27, en: 'They came again to Jerusalem, and as he was walking in the temple, the chief priests, and the scribes, and the elders came to him,', pt: 'Vieram de novo a Jerusalém. E andando Jesus pelo templo, aproximaram-se dele os principais sacerdotes, os escribas e os anciãos,' },
      { v: 28, en: 'and they began saying to him, “By what authority do you do these things? Or who gave you this authority to do these things?”', pt: 'que lhe perguntaram: Com que autoridade fazes tu estas coisas? ou quem te deu autoridade para fazê-las?' },
      { v: 29, en: 'Jesus said to them, “I will ask you one question. Answer me, and I will tell you by what authority I do these things.', pt: 'Respondeu-lhes Jesus: Eu vos perguntarei uma coisa; respondei-me, pois, e eu vos direi com que autoridade faço estas coisas.' },
      { v: 30, en: 'The baptism of John—was it from heaven, or from men? Answer me.”', pt: 'O batismo de João era do céu, ou dos homens? respondei-me.' },
      { v: 31, en: 'They reasoned with themselves, saying, “If we should say, ‘From heaven;’ he will say, ‘Why then did you not believe him?’', pt: 'Ao que eles arrazoavam entre si: Se dissermos: Do céu, ele dirá: Então por que não o crestes?' },
      { v: 32, en: 'If we should say, ‘From men’”—they feared the people, for all held John to really be a prophet.', pt: 'Mas diremos, porventura: Dos homens? - É que temiam o povo; porque todos verdadeiramente tinham a João como profeta.' },
      { v: 33, en: 'They answered Jesus, “We don’t know.” Jesus said to them, “Neither do I tell you by what authority I do these things.”', pt: 'Responderam, pois, a Jesus: Não sabemos. Replicou-lhes ele: Nem eu vos digo com que autoridade faço estas coisas.' },
    ],
    12: [
      { v: 1, en: 'He began to speak to them in parables. “A man planted a vineyard, put a hedge around it, dug a pit for the wine press, built a tower, rented it out to a farmer, and went into another country.', pt: 'Então começou Jesus a falar-lhes por parábolas. Um homem plantou uma vinha, cercou-a com uma sebe, cavou um lagar, e edificou uma torre; depois arrendou-a a uns lavradores e ausentou-se do país.' },
      { v: 2, en: 'When it was time, he sent a servant to the farmer to get from the farmer his share of the fruit of the vineyard.', pt: 'No tempo próprio, enviou um servo aos lavradores para que deles recebesse do fruto da vinha.' },
      { v: 3, en: 'They took him, beat him, and sent him away empty.', pt: 'Mas estes, apoderando-se dele, o espancaram e o mandaram embora de mãos vazias.' },
      { v: 4, en: 'Again, he sent another servant to them; and they threw stones at him, wounded him in the head, and sent him away shamefully treated.', pt: 'E tornou a enviar-lhes outro servo; e a este feriram na cabeça e o ultrajaram.' },
      { v: 5, en: 'Again he sent another; and they killed him; and many others, beating some, and killing some.', pt: 'Então enviou ainda outro, e a este mataram; e a outros muitos, dos quais a uns espancaram e a outros mataram.' },
      { v: 6, en: 'Therefore still having one, his beloved son, he sent him last to them, saying, ‘They will respect my son.’', pt: 'Ora, tinha ele ainda um, o seu filho amado; a este lhes enviou por último, dizendo: A meu filho terão respeito.' },
      { v: 7, en: 'But those farmers said among themselves, ‘This is the heir. Come, let’s kill him, and the inheritance will be ours.’', pt: 'Mas aqueles lavradores disseram entre si: Este é o herdeiro; vinde, matemo-lo, e a herança será nossa.' },
      { v: 8, en: 'They took him, killed him, and cast him out of the vineyard.', pt: 'E, agarrando-o, o mataram, e o lançaram fora da vinha.' },
      { v: 9, en: 'What therefore will the lord of the vineyard do? He will come and destroy the farmers, and will give the vineyard to others.', pt: 'Que fará, pois, o senhor da vinha? Virá e destruirá os lavradores, e dará a vinha a outros.' },
      { v: 10, en: 'Haven’t you even read this Scripture: ‘The stone which the builders rejected, the same was made the head of the corner.', pt: 'Nunca lestes esta escritura: A pedra que os edificadores rejeitaram, essa foi posta como pedra angular;' },
      { v: 11, en: 'This was from the Lord, it is marvelous in our eyes’?”', pt: 'pelo Senhor foi feito isso, e é maravilhoso aos nossos olhos?' },
      { v: 12, en: 'They tried to seize him, but they feared the multitude; for they perceived that he spoke the parable against them. They left him, and went away.', pt: 'Procuravam então prendê-lo, mas temeram a multidão, pois perceberam que contra eles proferira essa parábola; e, deixando-o, se retiraram.' },
      { v: 13, en: 'They sent some of the Pharisees and the Herodians to him, that they might trap him with words.', pt: 'Enviaram-lhe então alguns dos fariseus e dos herodianos, para que o apanhassem em alguma palavra.' },
      { v: 14, en: 'When they had come, they asked him, “Teacher, we know that you are honest, and don’t defer to anyone; for you aren’t partial to anyone, but truly teach the way of God. Is it lawful to pay taxes to Caesar, or not?', pt: 'Aproximando-se, pois, disseram-lhe: Mestre, sabemos que és verdadeiro, e de ninguém se te dá; porque não olhas à aparência dos homens, mas ensinas segundo a verdade o caminho de Deus; é lícito dar tributo a César, ou não? Daremos, ou não daremos?' },
      { v: 15, en: 'Shall we give, or shall we not give?” But he, knowing their hypocrisy, said to them, “Why do you test me? Bring me a denarius, that I may see it.”', pt: 'Mas Jesus, percebendo a hipocrisia deles, respondeu-lhes: Por que me experimentais? trazei-me um denário para que eu o veja.' },
      { v: 16, en: 'They brought it. He said to them, “Whose is this image and inscription?” They said to him, “Caesar’s.”', pt: 'E eles lho trouxeram. Perguntou-lhes Jesus: De quem é esta imagem e inscrição? Responderam-lhe: De César.' },
      { v: 17, en: 'Jesus answered them, “Render to Caesar the things that are Caesar’s, and to God the things that are God’s.” They marveled greatly at him.', pt: 'Disse-lhes Jesus: Dai, pois, a César o que é de César, e a Deus o que é de Deus. E admiravam-se dele.' },
      { v: 18, en: 'There came to him Sadducees, who say that there is no resurrection. They asked him, saying,', pt: 'Então se aproximaram dele alguns dos saduceus, que dizem não haver ressurreição, e lhe perguntaram, dizendo:' },
      { v: 19, en: '“Teacher, Moses wrote to us, ‘If a man’s brother dies, and leaves a wife behind him, and leaves no children, that his brother should take his wife, and raise up offspring for his brother.’', pt: 'Mestre, Moisés nos deixou escrito que se morrer alguém, deixando mulher sem deixar filhos, o irmão dele case com a mulher, e suscite descendência ao irmão.' },
      { v: 20, en: 'There were seven brothers. The first took a wife, and dying left no offspring.', pt: 'Ora, havia sete irmãos; o primeiro casou-se e morreu sem deixar descendência;' },
      { v: 21, en: 'The second took her, and died, leaving no children behind him. The third likewise;', pt: 'o segundo casou-se com a viúva, e morreu, não deixando descendência; e da mesma forma, o terceiro; e assim os sete, e não deixaram descendência.' },
      { v: 22, en: 'and the seven took her and left no children. Last of all the woman also died.', pt: 'Depois de todos, morreu também a mulher.' },
      { v: 23, en: 'In the resurrection, when they rise, whose wife will she be of them? For the seven had her as a wife.”', pt: 'Na ressurreição, de qual deles será ela esposa, pois os sete por esposa a tiveram?' },
      { v: 24, en: 'Jesus answered them, “Isn’t this because you are mistaken, not knowing the Scriptures, nor the power of God?', pt: 'Respondeu-lhes Jesus: Porventura não errais vós em razão de não compreenderdes as Escrituras nem o poder de Deus?' },
      { v: 25, en: 'For when they will rise from the dead, they neither marry, nor are given in marriage, but are like angels in heaven.', pt: 'Porquanto, ao ressuscitarem dos mortos, nem se casam, nem se dão em casamento; pelo contrário, são como os anjos nos céus.' },
      { v: 26, en: 'But about the dead, that they are raised; haven’t you read in the book of Moses, about the Bush, how God spoke to him, saying, ‘I am the God of Abraham, the God of Isaac, and the God of Jacob’?', pt: 'Quanto aos mortos, porém, serem ressuscitados, não lestes no livro de Moisés, onde se fala da sarça, como Deus lhe disse: Eu sou o Deus de Abraão, o Deus de Isaque e o Deus de Jacó?' },
      { v: 27, en: 'He is not the God of the dead, but of the living. You are therefore badly mistaken.”', pt: 'Ora, ele não é Deus de mortos, mas de vivos. Estais em grande erro.' },
      { v: 28, en: 'One of the scribes came, and heard them questioning together. Knowing that he had answered them well, asked him, “Which commandment is the greatest of all?”', pt: 'Aproximou-se dele um dos escribas que os ouvira discutir e, percebendo que lhes havia respondido bem, perguntou-lhe: Qual é o primeiro de todos os mandamentos?' },
      { v: 29, en: 'Jesus answered, “The greatest is, ‘Hear, Israel, the Lord our God, the Lord is one:', pt: 'Respondeu Jesus: O primeiro é: Ouve, Israel, o Senhor nosso Deus é o único Senhor.' },
      { v: 30, en: 'you shall love the Lord your God with all your heart, and with all your soul, and with all your mind, and with all your strength.’ This is the first commandment.', pt: 'Amarás, pois, ao Senhor teu Deus de todo o teu coração, de toda a tua alma, de todo o teu entendimento e de todas as tuas forças.' },
      { v: 31, en: 'The second is like this, ‘You shall love your neighbor as yourself.’ There is no other commandment greater than these.”', pt: 'E o segundo é este: Amarás ao teu próximo como a ti mesmo. Não há outro mandamento maior do que esses.' },
      { v: 32, en: 'The scribe said to him, “Truly, teacher, you have said well that he is one, and there is none other but he,', pt: 'Ao que lhe disse o escriba: Muito bem, Mestre; com verdade disseste que ele é um, e fora dele não há outro;' },
      { v: 33, en: 'and to love him with all the heart, and with all the understanding, with all the soul, and with all the strength, and to love his neighbor as himself, is more important than all whole burnt offerings and sacrifices.”', pt: 'e que amá-lo de todo o coração, de todo o entendimento e de todas as forças, e amar o próximo como a si mesmo, é mais do que todos os holocaustos e sacrifícios.' },
      { v: 34, en: 'When Jesus saw that he answered wisely, he said to him, “You are not far from God’s Kingdom.” No one dared ask him any question after that.', pt: 'E Jesus, vendo que havia respondido sabiamente, disse-lhe: Não estás longe do reino de Deus. E ninguém ousava mais interrogá-lo.' },
      { v: 35, en: 'Jesus responded, as he taught in the temple, “How is it that the scribes say that the Christ is the son of David?', pt: 'Por sua vez, Jesus, enquanto ensinava no templo, perguntou: Como é que os escribas dizem que o Cristo é filho de Davi?' },
      { v: 36, en: 'For David himself said in the Holy Spirit, ‘The Lord said to my Lord, “Sit at my right hand, until I make your enemies the footstool of your feet.”’', pt: 'O próprio Davi falou, movido pelo Espírito Santo: Disse o Senhor ao meu Senhor: Assenta-te à minha direita, até que eu ponha os teus inimigos debaixo dos teus pés.' },
      { v: 37, en: 'Therefore David himself calls him Lord, so how can he be his son?” The common people heard him gladly.', pt: 'Davi mesmo lhe chama Senhor; como é ele seu filho? E a grande multidão o ouvia com prazer.' },
      { v: 38, en: 'In his teaching he said to them, “Beware of the scribes, who like to walk in long robes, and to get greetings in the marketplaces,', pt: 'E prosseguindo ele no seu ensino, disse: Guardai-vos dos escribas, que gostam de andar com vestes compridas, e das saudações nas praças,' },
      { v: 39, en: 'and the best seats in the synagogues, and the best places at feasts:', pt: 'e dos primeiros assentos nas sinagogas, e dos primeiros lugares nos banquetes,' },
      { v: 40, en: 'those who devour widows’ houses, and for a pretense make long prayers. These will receive greater condemnation.”', pt: 'que devoram as casas das viúvas, e por pretexto fazem longas orações; estes hão de receber muito maior condenação.' },
      { v: 41, en: 'Jesus sat down opposite the treasury, and saw how the multitude cast money into the treasury. Many who were rich cast in much.', pt: 'E sentando-se Jesus defronte do cofre das ofertas, observava como a multidão lançava dinheiro no cofre; e muitos ricos deitavam muito.' },
      { v: 42, en: 'A poor widow came, and she cast in two small brass coins, which equal a quadrans coin.', pt: 'Vindo, porém, uma pobre viúva, lançou dois leptos, que valiam um quadrante.' },
      { v: 43, en: 'He called his disciples to himself, and said to them, “Most certainly I tell you, this poor widow gave more than all those who are giving into the treasury,', pt: 'E chamando ele os seus discípulos, disse-lhes: Em verdade vos digo que esta pobre viúva deu mais do que todos os que deitavam ofertas no cofre;' },
      { v: 44, en: 'for they all gave out of their abundance, but she, out of her poverty, gave all that she had to live on.”', pt: 'porque todos deram daquilo que lhes sobrava; mas esta, da sua pobreza, deu tudo o que tinha, mesmo todo o seu sustento.' },
    ],
    13: [
      { v: 1, en: 'As he went out of the temple, one of his disciples said to him, “Teacher, see what kind of stones and what kind of buildings!”', pt: 'Quando saía do templo, disse-lhe um dos seus discípulos: Mestre, olha que pedras e que edifícios!' },
      { v: 2, en: 'Jesus said to him, “Do you see these great buildings? There will not be left here one stone on another, which will not be thrown down.”', pt: 'Ao que Jesus lhe disse: Vês estes grandes edifícios? Não se deixará aqui pedra sobre pedra que não seja derribada.' },
      { v: 3, en: 'As he sat on the Mount of Olives opposite the temple, Peter, James, John, and Andrew asked him privately,', pt: 'Depois estando ele sentado no Monte das Oliveiras, defronte do templo, Pedro, Tiago, João e André perguntaram-lhe em particular:' },
      { v: 4, en: '“Tell us, when will these things be? What is the sign that these things are all about to be fulfilled?”', pt: 'Dize-nos, quando sucederão essas coisas, e que sinal haverá quando todas elas estiverem para se cumprir?' },
      { v: 5, en: 'Jesus, answering, began to tell them, “Be careful that no one leads you astray.', pt: 'Então Jesus começou a dizer-lhes: Acautelai-vos; ninguém vos engane;' },
      { v: 6, en: 'For many will come in my name, saying, ‘I am he!’ and will lead many astray.', pt: 'muitos virão em meu nome, dizendo: Sou eu; e a muitos enganarão.' },
      { v: 7, en: '“When you hear of wars and rumors of wars, don’t be troubled. For those must happen, but the end is not yet.', pt: 'Quando, porém, ouvirdes falar em guerras e rumores de guerras, não vos perturbeis; forçoso é que assim aconteça: mas ainda não é o fim.' },
      { v: 8, en: 'For nation will rise against nation, and kingdom against kingdom. There will be earthquakes in various places. There will be famines and troubles. These things are the beginning of birth pains.', pt: 'Pois se levantará nação contra nação, e reino contra reino; e haverá terremotos em diversos lugares, e haverá fomes. Isso será o princípio das dores.' },
      { v: 9, en: 'But watch yourselves, for they will deliver you up to councils. You will be beaten in synagogues. You will stand before rulers and kings for my sake, for a testimony to them.', pt: 'Mas olhai por vós mesmos; pois por minha causa vos hão de entregar aos sinédrios e às sinagogas, e sereis açoitados; também sereis levados perante governadores e reis, para lhes servir de testemunho.' },
      { v: 10, en: 'The Good News must first be preached to all the nations.', pt: 'Mas importa que primeiro o evangelho seja pregado entre todas as nações.' },
      { v: 11, en: 'When they lead you away and deliver you up, don’t be anxious beforehand, or premeditate what you will say, but say whatever will be given you in that hour. For it is not you who speak, but the Holy Spirit.', pt: 'Quando, pois, vos conduzirem para vos entregar, não vos preocupeis com o que haveis de dizer; mas, o que vos for dado naquela hora, isso falai; porque não sois vós que falais, mas sim o Espírito Santo.' },
      { v: 12, en: '“Brother will deliver up brother to death, and the father his child. Children will rise up against parents, and cause them to be put to death.', pt: 'Um irmão entregará à morte a seu irmão, e um pai a seu filho; e filhos se levantarão contra os pais e os matarão.' },
      { v: 13, en: 'You will be hated by all men for my name’s sake, but he who endures to the end, the same will be saved.', pt: 'E sereis odiados de todos por causa do meu nome; mas aquele que perseverar até o fim, esse será salvo.' },
      { v: 14, en: 'But when you see the abomination of desolation, spoken of by Daniel the prophet, standing where it ought not (let the reader understand), then let those who are in Judea flee to the mountains,', pt: 'Ora, quando vós virdes a abominação da desolação estar onde não deve estar (quem lê, entenda), então os que estiverem na Judéia fujam para os montes;' },
      { v: 15, en: 'and let him who is on the housetop not go down, nor enter in, to take anything out of his house.', pt: 'quem estiver no eirado não desça, nem entre para tirar alguma coisa da sua casa;' },
      { v: 16, en: 'Let him who is in the field not return back to take his cloak.', pt: 'e quem estiver no campo não volte atrás para buscar a sua capa.' },
      { v: 17, en: 'But woe to those who are with child and to those who nurse babies in those days!', pt: 'Mas ai das que estiverem grávidas, e das que amamentarem naqueles dias!' },
      { v: 18, en: 'Pray that your flight won’t be in the winter.', pt: 'Orai, pois, para que isto não suceda no inverno;' },
      { v: 19, en: 'For in those days there will be oppression, such as there has not been the like from the beginning of the creation which God created until now, and never will be.', pt: 'porque naqueles dias haverá uma tribulação tal, qual nunca houve desde o princípio da criação, que Deus criou, até agora, nem jamais haverá.' },
      { v: 20, en: 'Unless the Lord had shortened the days, no flesh would have been saved; but for the sake of the chosen ones, whom he picked out, he shortened the days.', pt: 'Se o Senhor não abreviasse aqueles dias, ninguém se salvaria mas ele, por causa dos eleitos que escolheu, abreviou aqueles dias.' },
      { v: 21, en: 'Then if anyone tells you, ‘Look, here is the Christ!’ or, ‘Look, there!’ don’t believe it.', pt: 'Então, se alguém vos disser: Eis aqui o Cristo! ou: Ei-lo ali! não acrediteis.' },
      { v: 22, en: 'For there will arise false christs and false prophets, and will show signs and wonders, that they may lead astray, if possible, even the chosen ones.', pt: 'Porque hão de surgir falsos cristos e falsos profetas, e farão sinais e prodígios para enganar, se possível, até os escolhidos.' },
      { v: 23, en: 'But you watch. “Behold, I have told you all things beforehand.', pt: 'Ficai vós, pois, de sobreaviso; eis que de antemão vos tenho dito tudo.' },
      { v: 24, en: 'But in those days, after that oppression, the sun will be darkened, the moon will not give its light,', pt: 'Mas naqueles dias, depois daquela tribulação, o sol escurecerá, e a lua não dará a sua luz;' },
      { v: 25, en: 'the stars will be falling from the sky, and the powers that are in the heavens will be shaken.', pt: 'as estrelas cairão do céu, e os poderes que estão nos céus, serão abalados.' },
      { v: 26, en: 'Then they will see the Son of Man coming in clouds with great power and glory.', pt: 'Então verão vir o Filho do homem nas nuvens, com grande poder e glória.' },
      { v: 27, en: 'Then he will send out his angels, and will gather together his chosen ones from the four winds, from the ends of the earth to the ends of the sky.', pt: 'E logo enviará os seus anjos, e ajuntará os seus eleitos, desde os quatro ventos, desde a extremidade da terra até a extremidade do céu.' },
      { v: 28, en: '“Now from the fig tree, learn this parable. When the branch has now become tender, and produces its leaves, you know that the summer is near;', pt: 'Da figueira, pois, aprendei a parábola: Quando já o seu ramo se torna tenro e brota folhas, sabeis que está próximo o verão.' },
      { v: 29, en: 'even so you also, when you see these things coming to pass, know that it is near, at the doors.', pt: 'Assim também vós, quando virdes sucederem essas coisas, sabei que ele está próximo, mesmo às portas.' },
      { v: 30, en: 'Most certainly I say to you, this generation will not pass away until all these things happen.', pt: 'Em verdade vos digo que não passará esta geração, até que todas essas coisas aconteçam.' },
      { v: 31, en: 'Heaven and earth will pass away, but my words will not pass away.', pt: 'Passará o céu e a terra, mas as minhas palavras não passarão.' },
      { v: 32, en: 'But of that day or that hour no one knows, not even the angels in heaven, nor the Son, but only the Father.', pt: 'Quanto, porém, ao dia e à hora, ninguém sabe, nem os anjos no céu nem o Filho, senão o Pai.' },
      { v: 33, en: 'Watch, keep alert, and pray; for you don’t know when the time is.', pt: 'Olhai! vigiai! porque não sabeis quando chegará o tempo.' },
      { v: 34, en: '“It is like a man, traveling to another country, having left his house, and given authority to his servants, and to each one his work, and also commanded the doorkeeper to keep watch.', pt: 'É como se um homem, devendo viajar, ao deixar a sua casa, desse autoridade aos seus servos, a cada um o seu trabalho, e ordenasse também ao porteiro que vigiasse.' },
      { v: 35, en: 'Watch therefore, for you don’t know when the lord of the house is coming, whether at evening, or at midnight, or when the rooster crows, or in the morning;', pt: 'Vigiai, pois; porque não sabeis quando virá o senhor da casa; se à tarde, se à meia-noite, se ao cantar do galo, se pela manhã;' },
      { v: 36, en: 'lest coming suddenly he might find you sleeping.', pt: 'para que, vindo de improviso, não vos ache dormindo.' },
      { v: 37, en: 'What I tell you, I tell all: Watch.”', pt: 'O que vos digo a vós, a todos o digo: Vigiai.' },
    ],
    14: [
      { v: 1, en: 'It was now two days before the feast of the Passover and the unleavened bread, and the chief priests and the scribes sought how they might seize him by deception, and kill him.', pt: 'Ora, dali a dois dias era a páscoa e a festa dos pães ázimos; e os principais sacerdotes e os escribas andavam buscando como prender Jesus a traição, para o matarem.' },
      { v: 2, en: 'For they said, “Not during the feast, because there might be a riot among the people.”', pt: 'Pois eles diziam: Não durante a festa, para que não haja tumulto entre o povo.' },
      { v: 3, en: 'While he was at Bethany, in the house of Simon the leper, as he sat at the table, a woman came having an alabaster jar of ointment of pure nard—very costly. She broke the jar, and poured it over his head.', pt: 'Estando ele em Betânia, reclinado à mesa em casa de Simão, o leproso, veio uma mulher que trazia um vaso de alabastro cheio de bálsamo de nardo puro, de grande preço; e, quebrando o vaso, derramou-lhe sobre a cabeça o bálsamo.' },
      { v: 4, en: 'But there were some who were indignant among themselves, saying, “Why has this ointment been wasted?', pt: 'Mas alguns houve que em si mesmos se indignaram e disseram: Para que se fez este desperdício do bálsamo?' },
      { v: 5, en: 'For this might have been sold for more than three hundred denarii, and given to the poor.” They grumbled against her.', pt: 'Pois podia ser vendido por mais de trezentos denários que se dariam aos pobres. E bramavam contra ela.' },
      { v: 6, en: 'But Jesus said, “Leave her alone. Why do you trouble her? She has done a good work for me.', pt: 'Jesus, porém, disse: Deixai-a; por que a molestais? Ela praticou uma boa ação para comigo.' },
      { v: 7, en: 'For you always have the poor with you, and whenever you want to, you can do them good; but you will not always have me.', pt: 'Porquanto os pobres sempre os tendes convosco e, quando quiserdes, podeis fazer-lhes bem; a mim, porém, nem sempre me tendes.' },
      { v: 8, en: 'She has done what she could. She has anointed my body beforehand for the burying.', pt: 'ela fez o que pode; antecipou-se a ungir o meu corpo para a sepultura.' },
      { v: 9, en: 'Most certainly I tell you, wherever this Good News may be preached throughout the whole world, that which this woman has done will also be spoken of for a memorial of her.”', pt: 'Em verdade vos digo que, em todo o mundo, onde quer que for pregado o evangelho, também o que ela fez será contado para memória sua.' },
      { v: 10, en: 'Judas Iscariot, who was one of the twelve, went away to the chief priests, that he might deliver him to them.', pt: 'Então Judas Iscariotes, um dos doze, foi ter com os principais sacerdotes para lhes entregar Jesus.' },
      { v: 11, en: 'They, when they heard it, were glad, and promised to give him money. He sought how he might conveniently deliver him.', pt: 'Ouvindo-o eles, alegraram-se, e prometeram dar-lhe dinheiro. E buscava como o entregaria em ocasião oportuna.' },
      { v: 12, en: 'On the first day of unleavened bread, when they sacrificed the Passover, his disciples asked him, “Where do you want us to go and prepare that you may eat the Passover?”', pt: 'Ora, no primeiro dia dos pães ázimos, quando imolavam a páscoa, disseram-lhe seus discípulos: Aonde queres que vamos fazer os preparativos para comeres a páscoa?' },
      { v: 13, en: 'He sent two of his disciples, and said to them, “Go into the city, and there you will meet a man carrying a pitcher of water. Follow him,', pt: 'Enviou, pois, dois dos seus discípulos, e disse-lhes: Ide à cidade, e vos sairá ao encontro um homem levando um cântaro de água; seguí-o;' },
      { v: 14, en: 'and wherever he enters in, tell the master of the house, ‘The Teacher says, “Where is the guest room, where I may eat the Passover with my disciples?”’', pt: 'e, onde ele entrar, dizei ao dono da casa: O Mestre manda perguntar: Onde está o meu aposento em que hei de comer a páscoa com os meus discípulos?' },
      { v: 15, en: 'He will himself show you a large upper room furnished and ready. Get ready for us there.”', pt: 'E ele vos mostrará um grande cenáculo mobiliado e pronto; aí fazei-nos os preparativos.' },
      { v: 16, en: 'His disciples went out, and came into the city, and found things as he had said to them, and they prepared the Passover.', pt: 'Partindo, pois, os discípulos, foram à cidade, onde acharam tudo como ele lhes dissera, e prepararam a páscoa.' },
      { v: 17, en: 'When it was evening he came with the twelve.', pt: 'Ao anoitecer chegou ele com os doze.' },
      { v: 18, en: 'As they sat and were eating, Jesus said, “Most certainly I tell you, one of you will betray me—he who eats with me.”', pt: 'E, quando estavam reclinados à mesa e comiam, disse Jesus: Em verdade vos digo que um de vós, que comigo come, há de trair-me.' },
      { v: 19, en: 'They began to be sorrowful, and to ask him one by one, “Surely not I?” And another said, “Surely not I?”', pt: 'Ao que eles começaram a entristecer-se e a perguntar-lhe um após outro: Porventura sou eu?' },
      { v: 20, en: 'He answered them, “It is one of the twelve, he who dips with me in the dish.', pt: 'Respondeu-lhes: É um dos doze, que mete comigo a mão no prato.' },
      { v: 21, en: 'For the Son of Man goes, even as it is written about him, but woe to that man by whom the Son of Man is betrayed! It would be better for that man if he had not been born.”', pt: 'Pois o Filho do homem vai, conforme está escrito a seu respeito; mas ai daquele por quem o Filho do homem é traído! bom seria para esse homem se não houvera nascido.' },
      { v: 22, en: 'As they were eating, Jesus took bread, and when he had blessed, he broke it, and gave to them, and said, “Take, eat. This is my body.”', pt: 'Enquanto comiam, Jesus tomou pão e, abençoando-o, o partiu e deu-lho, dizendo: Tomai; isto é o meu corpo.' },
      { v: 23, en: 'He took the cup, and when he had given thanks, he gave to them. They all drank of it.', pt: 'E tomando um cálice, rendeu graças e deu-lho; e todos beberam dele.' },
      { v: 24, en: 'He said to them, “This is my blood of the new covenant, which is poured out for many.', pt: 'E disse-lhes: Isto é o meu sangue, o sangue do pacto, que por muitos é derramado.' },
      { v: 25, en: 'Most certainly I tell you, I will no more drink of the fruit of the vine, until that day when I drink it anew in God’s Kingdom.”', pt: 'Em verdade vos digo que não beberei mais do fruto da videira, até aquele dia em que o beber, novo, no reino de Deus.' },
      { v: 26, en: 'When they had sung a hymn, they went out to the Mount of Olives.', pt: 'E, tendo cantado um hino, saíram para o Monte das Oliveiras.' },
      { v: 27, en: 'Jesus said to them, “All of you will be made to stumble because of me tonight, for it is written, ‘I will strike the shepherd, and the sheep will be scattered.’', pt: 'Disse-lhes então Jesus: Todos vós vos escandalizareis; porque escrito está: Ferirei o pastor, e as ovelhas se dispersarão.' },
      { v: 28, en: 'However, after I am raised up, I will go before you into Galilee.”', pt: 'Todavia, depois que eu ressurgir, irei adiante de vós para a Galiléia.' },
      { v: 29, en: 'But Peter said to him, “Although all will be offended, yet I will not.”', pt: 'Ao que Pedro lhe disse: Ainda que todos se escandalizem, nunca, porém, eu.' },
      { v: 30, en: 'Jesus said to him, “Most certainly I tell you, that you today, even this night, before the rooster crows twice, you will deny me three times.”', pt: 'Replicou-lhe Jesus: Em verdade te digo que hoje, nesta noite, antes que o galo cante duas vezes, três vezes tu me negarás.' },
      { v: 31, en: 'But he spoke all the more, “If I must die with you, I will not deny you.” They all said the same thing.', pt: 'Mas ele repetia com veemência: Ainda que me seja necessário morrer contigo, de modo nenhum te negarei. Assim também diziam todos.' },
      { v: 32, en: 'They came to a place which was named Gethsemane. He said to his disciples, “Sit here, while I pray.”', pt: 'Então chegaram a um lugar chamado Getsêmane, e disse Jesus a seus discípulos: Sentai-vos aqui, enquanto eu oro.' },
      { v: 33, en: 'He took with him Peter, James, and John, and began to be greatly troubled and distressed.', pt: 'E levou consigo a Pedro, a Tiago e a João, e começou a ter pavor e a angustiar-se;' },
      { v: 34, en: 'He said to them, “My soul is exceedingly sorrowful, even to death. Stay here, and watch.”', pt: 'e disse-lhes: A minha alma está triste até a morte; ficai aqui e vigiai.' },
      { v: 35, en: 'He went forward a little, and fell on the ground, and prayed that, if it were possible, the hour might pass away from him.', pt: 'E adiantando-se um pouco, prostrou-se em terra; e orava para que, se fosse possível, passasse dele aquela hora.' },
      { v: 36, en: 'He said, “Abba, Father, all things are possible to you. Please remove this cup from me. However, not what I desire, but what you desire.”', pt: 'E dizia: Aba, Pai, tudo te é possível; afasta de mim este cálice; todavia não seja o que eu quero, mas o que tu queres.' },
      { v: 37, en: 'He came and found them sleeping, and said to Peter, “Simon, are you sleeping? Couldn’t you watch one hour?', pt: 'Voltando, achou-os dormindo; e disse a Pedro: Simão, dormes? não pudeste vigiar uma hora?' },
      { v: 38, en: 'Watch and pray, that you may not enter into temptation. The spirit indeed is willing, but the flesh is weak.”', pt: 'Vigiai e orai, para que não entreis em tentação; o espírito, na verdade, está pronto, mas a carne é fraca.' },
      { v: 39, en: 'Again he went away, and prayed, saying the same words.', pt: 'Retirou-se de novo e orou, dizendo as mesmas palavras.' },
      { v: 40, en: 'Again he returned, and found them sleeping, for their eyes were very heavy, and they didn’t know what to answer him.', pt: 'E voltando outra vez, achou-os dormindo, porque seus olhos estavam carregados; e não sabiam o que lhe responder.' },
      { v: 41, en: 'He came the third time, and said to them, “Sleep on now, and take your rest. It is enough. The hour has come. Behold, the Son of Man is betrayed into the hands of sinners.', pt: 'Ao voltar pela terceira vez, disse-lhes: Dormi agora e descansai. - Basta; é chegada a hora. Eis que o Filho do homem está sendo entregue nas mãos dos pecadores.' },
      { v: 42, en: 'Arise, let us be going. Behold, he who betrays me is at hand.”', pt: 'Levantai-vos, vamo-nos; eis que é chegado aquele que me trai.' },
      { v: 43, en: 'Immediately, while he was still speaking, Judas, one of the twelve, came—and with him a multitude with swords and clubs, from the chief priests, the scribes, and the elders.', pt: 'E logo, enquanto ele ainda falava, chegou Judas, um dos doze, e com ele uma multidão com espadas e varapaus, vinda da parte dos principais sacerdotes, dos escribas e dos anciãos.' },
      { v: 44, en: 'Now he who betrayed him had given them a sign, saying, “Whomever I will kiss, that is he. Seize him, and lead him away safely.”', pt: 'Ora, o que o traía lhes havia dado um sinal, dizendo: Aquele que eu beijar, esse é; prendei-o e levai-o com segurança.' },
      { v: 45, en: 'When he had come, immediately he came to him, and said, “Rabbi! Rabbi!” and kissed him.', pt: 'E, logo que chegou, aproximando-se de Jesus, disse: Rabi! E o beijou.' },
      { v: 46, en: 'They laid their hands on him, and seized him.', pt: 'Ao que eles lhes lançaram as mãos, e o prenderam.' },
      { v: 47, en: 'But a certain one of those who stood by drew his sword, and struck the servant of the high priest, and cut off his ear.', pt: 'Mas um dos que ali estavam, puxando da espada, feriu o servo do sumo sacerdote e cortou-lhe uma orelha.' },
      { v: 48, en: 'Jesus answered them, “Have you come out, as against a robber, with swords and clubs to seize me?', pt: 'Disse-lhes Jesus: Saístes com espadas e varapaus para me prender, como a um salteador?' },
      { v: 49, en: 'I was daily with you in the temple teaching, and you didn’t arrest me. But this is so that the Scriptures might be fulfilled.”', pt: 'Todos os dias estava convosco no templo, a ensinar, e não me prendestes; mas isto é para que se cumpram as Escrituras.' },
      { v: 50, en: 'They all left him, and fled.', pt: 'Nisto, todos o deixaram e fugiram.' },
      { v: 51, en: 'A certain young man followed him, having a linen cloth thrown around himself over his naked body. The young men grabbed him,', pt: 'Ora, seguia-o certo jovem envolto em um lençol sobre o corpo nu; e o agarraram.' },
      { v: 52, en: 'but he left the linen cloth, and fled from them naked.', pt: 'Mas ele, largando o lençol, fugiu despido.' },
      { v: 53, en: 'They led Jesus away to the high priest. All the chief priests, the elders, and the scribes came together with him.', pt: 'Levaram Jesus ao sumo sacerdote, e ajuntaram-se todos os principais sacerdotes, os anciãos e os escribas.' },
      { v: 54, en: 'Peter had followed him from a distance, until he came into the court of the high priest. He was sitting with the officers, and warming himself in the light of the fire.', pt: 'E Pedro o seguiu de longe até dentro do pátio do sumo sacerdote, e estava sentado com os guardas, aquentando-se ao fogo.' },
      { v: 55, en: 'Now the chief priests and the whole council sought witnesses against Jesus to put him to death, and found none.', pt: 'Os principais sacerdotes testemunho contra Jesus para o matar, e não o achavam.' },
      { v: 56, en: 'For many gave false testimony against him, and their testimony didn’t agree with each other.', pt: 'Porque contra ele muitos depunham falsamente, mas os testemunhos não concordavam.' },
      { v: 57, en: 'Some stood up, and gave false testimony against him, saying,', pt: 'Levantaram-se por fim alguns que depunham falsamente contra ele, dizendo:' },
      { v: 58, en: '“We heard him say, ‘I will destroy this temple that is made with hands, and in three days I will build another made without hands.’”', pt: 'Nós o ouvimos dizer: Eu destruirei este santuário, construído por mãos de homens, e em três dias edificarei outro, não feito por mãos de homens.' },
      { v: 59, en: 'Even so, their testimony did not agree.', pt: 'E nem assim concordava o seu testemunho.' },
      { v: 60, en: 'The high priest stood up in the middle, and asked Jesus, “Have you no answer? What is it which these testify against you?”', pt: 'Levantou-se então o sumo sacerdote no meio e perguntou a Jesus: Não respondes coisa alguma? Que é que estes depõem conta ti?' },
      { v: 61, en: 'But he stayed quiet, and answered nothing. Again the high priest asked him, “Are you the Christ, the Son of the Blessed?”', pt: 'Ele, porém, permaneceu calado, e nada respondeu. Tornou o sumo sacerdote a interrogá-lo, perguntando-lhe: És tu o Cristo, o Filho do Deus bendito?' },
      { v: 62, en: 'Jesus said, “I am. You will see the Son of Man sitting at the right hand of Power, and coming with the clouds of the sky.”', pt: 'Respondeu Jesus: Eu o sou; e vereis o Filho do homem assentado à direita do Poder e vindo com as nuvens do céu.' },
      { v: 63, en: 'The high priest tore his clothes, and said, “What further need have we of witnesses?', pt: 'Então o sumo sacerdote, rasgando as suas vestes, disse: Para que precisamos ainda de testemunhas?' },
      { v: 64, en: 'You have heard the blasphemy! What do you think?” They all condemned him to be worthy of death.', pt: 'Acabais de ouvir a blasfêmia; que vos parece? E todos o condenaram como réu de morte.' },
      { v: 65, en: 'Some began to spit on him, and to cover his face, and to beat him with fists, and to tell him, “Prophesy!” The officers struck him with the palms of their hands.', pt: 'E alguns começaram a cuspir nele, e a cobrir-lhe o rosto, e a dar-lhe socos, e a dizer-lhe: Profetiza. E os guardas receberam-no a bofetadas.' },
      { v: 66, en: 'As Peter was in the courtyard below, one of the maids of the high priest came,', pt: 'Ora, estando Pedro em baixo, no átrio, chegou uma das criadas do sumo sacerdote' },
      { v: 67, en: 'and seeing Peter warming himself, she looked at him, and said, “You were also with the Nazarene, Jesus!”', pt: 'e, vendo a Pedro, que se estava aquentando, encarou-o e disse: Tu também estavas com o nazareno, esse Jesus.' },
      { v: 68, en: 'But he denied it, saying, “I neither know, nor understand what you are saying.” He went out on the porch, and the rooster crowed.', pt: 'Mas ele o negou, dizendo: Não sei nem compreendo o que dizes. E saiu para o alpendre.' },
      { v: 69, en: 'The maid saw him, and began again to tell those who stood by, “This is one of them.”', pt: 'E a criada, vendo-o, começou de novo a dizer aos que ali estavam: Esse é um deles.' },
      { v: 70, en: 'But he again denied it. After a little while again those who stood by said to Peter, “You truly are one of them, for you are a Galilean, and your speech shows it.”', pt: 'Mas ele o negou outra vez. E pouco depois os que ali estavam disseram novamente a Pedro: Certamente tu és um deles; pois és também galileu.' },
      { v: 71, en: 'But he began to curse, and to swear, “I don’t know this man of whom you speak!”', pt: 'Ele, porém, começou a praguejar e a jurar: Não conheço esse homem de quem falais.' },
      { v: 72, en: 'The rooster crowed the second time. Peter remembered the word, how that Jesus said to him, “Before the rooster crows twice, you will deny me three times.” When he thought about that, he wept.', pt: 'Nesse instante o galo cantou pela segunda vez. E Pedro lembrou-se da palavra que lhe dissera Jesus: Antes que o galo cante duas vezes, três vezes me negarás. E caindo em si, começou a chorar.' },
    ],
    15: [
      { v: 1, en: 'Immediately in the morning the chief priests, with the elders and scribes, and the whole council, held a consultation, and bound Jesus, and carried him away, and delivered him up to Pilate.', pt: 'Logo de manhã tiveram conselho os principais sacerdotes com os anciãos, os escribas e todo o sinédrio; e maniatando a Jesus, o levaram e o entregaram a Pilatos.' },
      { v: 2, en: 'Pilate asked him, “Are you the King of the Jews?” He answered, “So you say.”', pt: 'Pilatos lhe perguntou: És tu o rei dos judeus? Respondeu-lhe Jesus: É como dizes.' },
      { v: 3, en: 'The chief priests accused him of many things.', pt: 'e os principais dos sacerdotes o acusavam de muitas coisas.' },
      { v: 4, en: 'Pilate again asked him, “Have you no answer? See how many things they testify against you!”', pt: 'Tornou Pilatos a interrogá-lo, dizendo: Não respondes nada? Vê quantas acusações te fazem.' },
      { v: 5, en: 'But Jesus made no further answer, so that Pilate marveled.', pt: 'Mas Jesus nada mais respondeu, de maneira que Pilatos se admirava.' },
      { v: 6, en: 'Now at the feast he used to release to them one prisoner, whom they asked of him.', pt: 'Ora, por ocasião da festa costumava soltar-lhes um preso qualquer que eles pedissem.' },
      { v: 7, en: 'There was one called Barabbas, bound with his fellow insurgents, men who in the insurrection had committed murder.', pt: 'E havia um, chamado Barrabás, preso com outros sediciosos, os quais num motim haviam cometido um homicídio.' },
      { v: 8, en: 'The multitude, crying aloud, began to ask him to do as he always did for them.', pt: 'E a multidão subiu e começou a pedir o que lhe costumava fazer.' },
      { v: 9, en: 'Pilate answered them, saying, “Do you want me to release to you the King of the Jews?”', pt: 'Ao que Pilatos lhes perguntou: Quereis que vos solte o rei dos judeus?' },
      { v: 10, en: 'For he perceived that for envy the chief priests had delivered him up.', pt: 'Pois ele sabia que por inveja os principais sacerdotes lho haviam entregado.' },
      { v: 11, en: 'But the chief priests stirred up the multitude, that he should release Barabbas to them instead.', pt: 'Mas os principais sacerdotes incitaram a multidão a pedir que lhes soltasse antes a Barrabás.' },
      { v: 12, en: 'Pilate again asked them, “What then should I do to him whom you call the King of the Jews?”', pt: 'E Pilatos, tornando a falar, perguntou-lhes: Que farei então daquele a quem chamais reis dos judeus?' },
      { v: 13, en: 'They cried out again, “Crucify him!”', pt: 'Novamente clamaram eles: Crucifica-o!' },
      { v: 14, en: 'Pilate said to them, “Why, what evil has he done?” But they cried out exceedingly, “Crucify him!”', pt: 'Disse-lhes Pilatos: Mas que mal fez ele? Ao que eles clamaram ainda mais: Crucifica-o!' },
      { v: 15, en: 'Pilate, wishing to please the multitude, released Barabbas to them, and handed over Jesus, when he had flogged him, to be crucified.', pt: 'Então Pilatos, querendo satisfazer a multidão, soltou-lhe Barrabás; e tendo mandado açoitar a Jesus, o entregou para ser crucificado.' },
      { v: 16, en: 'The soldiers led him away within the court, which is the Praetorium; and they called together the whole cohort.', pt: 'Os soldados, pois, levaram-no para dentro, ao pátio, que é o pretório, e convocaram toda a coorte;' },
      { v: 17, en: 'They clothed him with purple, and weaving a crown of thorns, they put it on him.', pt: 'vestiram-no de púrpura e puseram-lhe na cabeça uma coroa de espinhos que haviam tecido;' },
      { v: 18, en: 'They began to salute him, “Hail, King of the Jews!”', pt: 'e começaram a saudá-lo: Salve, rei dos judeus!' },
      { v: 19, en: 'They struck his head with a reed, and spat on him, and bowing their knees, did homage to him.', pt: 'Davam-lhe com uma cana na cabeça, cuspiam nele e, postos de joelhos, o adoravam.' },
      { v: 20, en: 'When they had mocked him, they took the purple off him, and put his own garments on him. They led him out to crucify him.', pt: 'Depois de o terem assim escarnecido, despiram-lhe a púrpura, e lhe puseram as vestes. Então o levaram para fora, a fim de o crucificarem.' },
      { v: 21, en: 'They compelled one passing by, coming from the country, Simon of Cyrene, the father of Alexander and Rufus, to go with them, that he might bear his cross.', pt: 'E obrigaram certo Simão, cireneu, pai de Alexandre e de Rufo, que por ali passava, vindo do campo, a carregar-lhe a cruz.' },
      { v: 22, en: 'They brought him to the place called Golgotha, which is, being interpreted, “The place of a skull.”', pt: 'Levaram-no, pois, ao lugar do Gólgota, que quer dizer, lugar da Caveira.' },
      { v: 23, en: 'They offered him wine mixed with myrrh to drink, but he didn’t take it.', pt: 'E ofereciam-lhe vinho misturado com mirra; mas ele não o tomou.' },
      { v: 24, en: 'Crucifying him, they parted his garments among them, casting lots on them, what each should take.', pt: 'Então o crucificaram, e repartiram entre si as vestes dele, lançando sortes sobre elas para ver o que cada um levaria.' },
      { v: 25, en: 'It was the third hour, and they crucified him.', pt: 'E era a hora terceira quando o crucificaram.' },
      { v: 26, en: 'The superscription of his accusation was written over him, “THE KING OF THE JEWS.”', pt: 'Por cima dele estava escrito o título da sua acusação: O REI DOS JUDEUS.' },
      { v: 27, en: 'With him they crucified two robbers; one on his right hand, and one on his left.', pt: 'Também, com ele, crucificaram dois salteadores, um à sua direita, e outro à esquerda.' },
      { v: 28, en: 'The Scripture was fulfilled, which says, “He was counted with transgressors.”', pt: '[E cumpriu-se a escritura que diz: E com os malfeitores foi contado.]' },
      { v: 29, en: 'Those who passed by blasphemed him, wagging their heads, and saying, “Ha! You who destroy the temple, and build it in three days,', pt: 'E os que iam passando blasfemavam dele, meneando a cabeça e dizendo: Ah! tu que destróis o santuário e em três dias o reedificas.' },
      { v: 30, en: 'save yourself, and come down from the cross!”', pt: 'salva-te a ti mesmo, descendo da cruz.' },
      { v: 31, en: 'Likewise, also the chief priests mocking among themselves with the scribes said, “He saved others. He can’t save himself.', pt: 'De igual modo também os principais sacerdotes, com os escribas, escarnecendo-o, diziam entre si: A outros salvou; a si mesmo não pode salvar;' },
      { v: 32, en: 'Let the Christ, the King of Israel, now come down from the cross, that we may see and believe him.” Those who were crucified with him also insulted him.', pt: 'desça agora da cruz o Cristo, o rei de Israel, para que vejamos e creiamos, Também os que com ele foram crucificados o injuriavam.' },
      { v: 33, en: 'When the sixth hour had come, there was darkness over the whole land until the ninth hour.', pt: 'E, chegada a hora sexta, houve trevas sobre a terra, até a hora nona.' },
      { v: 34, en: 'At the ninth hour Jesus cried with a loud voice, saying, “Eloi, Eloi, lama sabachthani?” which is, being interpreted, “My God, my God, why have you forsaken me?”', pt: 'E, à hora nona, bradou Jesus em alta voz: Eloí, Eloí, lamá, sabactani? que, traduzido, é: Deus meu, Deus meu, por que me desamparaste?' },
      { v: 35, en: 'Some of those who stood by, when they heard it, said, “Behold, he is calling Elijah.”', pt: 'Alguns dos que ali estavam, ouvindo isso, diziam: Eis que chama por Elias.' },
      { v: 36, en: 'One ran, and filling a sponge full of vinegar, put it on a reed, and gave it to him to drink, saying, “Let him be. Let’s see whether Elijah comes to take him down.”', pt: 'Correu um deles, ensopou uma esponja em vinagre e, pondo-a numa cana, dava-lhe de beber, dizendo: Deixai, vejamos se Elias virá tirá-lo.' },
      { v: 37, en: 'Jesus cried out with a loud voice, and gave up the spirit.', pt: 'Mas Jesus, dando um grande brado, expirou.' },
      { v: 38, en: 'The veil of the temple was torn in two from the top to the bottom.', pt: 'Então o véu do santuário se rasgou em dois, de alto a baixo.' },
      { v: 39, en: 'When the centurion, who stood by opposite him, saw that he cried out like this and breathed his last, he said, “Truly this man was the Son of God!”', pt: 'Ora, o centurião, que estava defronte dele, vendo-o assim expirar, disse: Verdadeiramente este homem era filho de Deus.' },
      { v: 40, en: 'There were also women watching from afar, among whom were both Mary Magdalene, and Mary the mother of James the less and of Joses, and Salome;', pt: 'Também ali estavam algumas mulheres olhando de longe, entre elas Maria Madalena, Maria, mãe de Tiago o Menor e de José, e Salomé;' },
      { v: 41, en: 'who, when he was in Galilee, followed him, and served him; and many other women who came up with him to Jerusalem.', pt: 'as quais o seguiam e o serviam quando ele estava na Galiléia; e muitas outras que tinham subido com ele a Jerusalém.' },
      { v: 42, en: 'When evening had now come, because it was the Preparation Day, that is, the day before the Sabbath,', pt: 'Ao cair da tarde, como era o dia da preparação, isto é, a véspera do sábado,' },
      { v: 43, en: 'Joseph of Arimathaea, a prominent council member who also himself was looking for God’s Kingdom, came. He boldly went in to Pilate, and asked for Jesus’ body.', pt: 'José de Arimatéia, ilustre membro do sinédrio, que também esperava o reino de Deus, cobrando ânimo foi Pilatos e pediu o corpo de Jesus.' },
      { v: 44, en: 'Pilate marveled if he were already dead; and summoning the centurion, he asked him whether he had been dead long.', pt: 'Admirou-se Pilatos de que já tivesse morrido; e chamando o centurião, perguntou-lhe se, de fato, havia morrido.' },
      { v: 45, en: 'When he found out from the centurion, he granted the body to Joseph.', pt: 'E, depois que o soube do centurião, cedeu o cadáver a José;' },
      { v: 46, en: 'He bought a linen cloth, and taking him down, wound him in the linen cloth, and laid him in a tomb which had been cut out of a rock. He rolled a stone against the door of the tomb.', pt: 'o qual, tendo comprado um pano de linho, tirou da cruz o corpo, envolveu-o no pano e o depositou num sepulcro aberto em rocha; e rolou uma pedra para a porta do sepulcro.' },
      { v: 47, en: 'Mary Magdalene and Mary, the mother of Joses, saw where he was laid.', pt: 'E Maria Madalena e Maria, mãe de José, observavam onde fora posto.' },
    ],
    16: [
      { v: 1, en: 'When the Sabbath was past, Mary Magdalene, and Mary the mother of James, and Salome, bought spices, that they might come and anoint him.', pt: 'Ora, passado o sábado, Maria Madalena, Maria, mãe de Tiago, e Salomé, compraram aromas para irem ungi-lo.' },
      { v: 2, en: 'Very early on the first day of the week, they came to the tomb when the sun had risen.', pt: 'E, no primeiro dia da semana, foram ao sepulcro muito cedo, ao levantar do sol.' },
      { v: 3, en: 'They were saying among themselves, “Who will roll away the stone from the door of the tomb for us?”', pt: 'E diziam umas às outras: Quem nos revolverá a pedra da porta do sepulcro?' },
      { v: 4, en: 'for it was very big. Looking up, they saw that the stone was rolled back.', pt: 'Mas, levantando os olhos, notaram que a pedra, que era muito grande, já estava revolvida;' },
      { v: 5, en: 'Entering into the tomb, they saw a young man sitting on the right side, dressed in a white robe, and they were amazed.', pt: 'e entrando no sepulcro, viram um moço sentado à direita, vestido de alvo manto; e ficaram atemorizadas.' },
      { v: 6, en: 'He said to them, “Don’t be amazed. You seek Jesus, the Nazarene, who has been crucified. He has risen. He is not here. Behold, the place where they laid him!', pt: 'Ele, porém, lhes disse: Não vos atemorizeis; buscais a Jesus, o nazareno, que foi crucificado; ele ressurgiu; não está aqui; eis o lugar onde o puseram.' },
      { v: 7, en: 'But go, tell his disciples and Peter, ‘He goes before you into Galilee. There you will see him, as he said to you.’”', pt: 'Mas ide, dizei a seus discípulos, e a Pedro, que ele vai adiante de vós para a Galiléia; ali o vereis, como ele vos disse.' },
      { v: 8, en: 'They went out, and fled from the tomb, for trembling and astonishment had come on them. They said nothing to anyone; for they were afraid.', pt: 'E, saindo elas, fugiram do sepulcro, porque estavam possuídas de medo e assombro; e não disseram nada a ninguém, porque temiam.' },
      { v: 9, en: 'Now when he had risen early on the first day of the week, he appeared first to Mary Magdalene, from whom he had cast out seven demons.', pt: '[Ora, havendo Jesus ressurgido cedo no primeiro dia da semana, apareceu primeiramente a Maria Madalena, da qual tinha expulsado sete demônios.' },
      { v: 10, en: 'She went and told those who had been with him, as they mourned and wept.', pt: 'Foi ela anunciá-lo aos que haviam andado com ele, os quais estavam tristes e chorando;' },
      { v: 11, en: 'When they heard that he was alive, and had been seen by her, they disbelieved.', pt: 'e ouvindo eles que vivia, e que tinha sido visto por ela, não o creram.' },
      { v: 12, en: 'After these things he was revealed in another form to two of them, as they walked, on their way into the country.', pt: 'Depois disso manifestou-se sob outra forma a dois deles que iam de caminho para o campo,' },
      { v: 13, en: 'They went away and told it to the rest. They didn’t believe them, either.', pt: 'os quais foram anunciá-lo aos outros; mas nem a estes deram crédito.' },
      { v: 14, en: 'Afterward he was revealed to the eleven themselves as they sat at the table, and he rebuked them for their unbelief and hardness of heart, because they didn’t believe those who had seen him after he had risen.', pt: 'Por último, então, apareceu aos onze, estando eles reclinados à mesa, e lançou-lhes em rosto a sua incredulidade e dureza de coração, por não haverem dado crédito aos que o tinham visto já ressurgido.' },
      { v: 15, en: 'He said to them, “Go into all the world, and preach the Good News to the whole creation.', pt: 'E disse-lhes: Ide por todo o mundo, e pregai o evangelho a toda criatura.' },
      { v: 16, en: 'He who believes and is baptized will be saved; but he who disbelieves will be condemned.', pt: 'Quem crer e for batizado será salvo; mas quem não crer será condenado.' },
      { v: 17, en: 'These signs will accompany those who believe: in my name they will cast out demons; they will speak with new languages;', pt: 'E estes sinais acompanharão aos que crerem: em meu nome expulsarão demônios; falarão novas línguas;' },
      { v: 18, en: 'they will take up serpents; and if they drink any deadly thing, it will in no way hurt them; they will lay hands on the sick, and they will recover.”', pt: 'pegarão em serpentes; e se beberem alguma coisa mortífera, não lhes fará dano algum; e porão as mãos sobre os enfermos, e estes serão curados.' },
      { v: 19, en: 'So then the Lord, after he had spoken to them, was received up into heaven, and sat down at the right hand of God.', pt: 'Ora, o Senhor, depois de lhes ter falado, foi recebido no céu, e assentou-se à direita de Deus.' },
      { v: 20, en: 'They went out, and preached everywhere, the Lord working with them, and confirming the word by the signs that followed. Amen.', pt: 'Eles, pois, saindo, pregaram por toda parte, cooperando com eles o Senhor, e confirmando a palavra com os sinais que os acompanhavam.]' },
    ],
  },
};

export default book;
